s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:216:\"The \"Do the Woo\" podcast is returning, focusing on WooCommerce insights, featuring industry leaders. It will include lively discussions, audience Q&#038;As, and monthly episodes with hosts James Kemp and Katie Keith.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 16 Dec 2025 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:36;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"Matt: Cloudflare CMS Stats\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150858\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://ma.tt/2025/12/cloudflare-cms-stats/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:684:\"<p>Cloudflare released their Radar report for 2025, one fun stat was they analyzed the top 5,000 domains, and it had some interesting results <a href=\"https://radar.cloudflare.com/year-in-review/2025#website-technologies\">for website technologies</a>. Open Source tech came in at 47% for WordPress and 4.7% for Drupal, <em>which wins the majority</em>! Then in proprietary there was Adobe at 16%, Contentful at 8%, Shopify at 1.9%&#8230;</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-150859\" height=\"383\" src=\"https://i0.wp.com/ma.tt/files/2025/12/cloudflare-website-tech-1024x649.png?resize=604%2C383&#038;quality=80&#038;ssl=1\" width=\"604\" /></figure>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 16 Dec 2025 00:41:56 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:37;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"Matt: Nex Playground\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150848\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:37:\"https://ma.tt/2025/12/nex-playground/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:855:\"<p>The Wall Street Journal has a fun article about the Nex Playground, <a href=\"https://www.wsj.com/business/entrepreneurship/nex-playground-toy-game-console-holiday-shopping-af47125f\">The Hottest Toy of the Year Is Made by a Tech Startup You’ve Never Heard Of</a>. It&#8217;s a very fun way to game with friends and stay active, so afterward you have that same great feeling like after playing a sport. I think this is the first time one of <a href=\"https://audrey.co/\">Audrey Capital&#8217;s companies</a> (we invested when it was <a href=\"https://www.homecourt.ai/\">the Homecourt app</a>) is the hot Christmas item. <a href=\"https://www.amazon.com/Playground-AI-Powered-Transforms-Not-Machine-Specific/dp/B0D2JGYX3F?tag=photomatt08-20&amp;th=1\">Here&#8217;s it on Amazon</a>, though it looks like it doesn&#8217;t ship before Christmas right now.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 15 Dec 2025 05:59:27 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:38;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Matt: Apple iWeb\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150841\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2025/12/apple-iweb/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1024:\"<p>The new X/Twitter algorithim is hard to predict, but I&#8217;ve had <a href=\"https://x.com/photomatt/status/1999769782279938531\">one go viral with over a million views now</a>, a quote-tweet of a cool demo video of Apple&#8217;s website builder from 2009, with themes and blog support and everything. Interesting to compare its interface to Gutenberg and WordPress today.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-rich is-provider-twitter wp-block-embed-twitter\"><div class=\"wp-block-embed__wrapper\">\n<div class=\"embed-twitter\"><blockquote class=\"twitter-tweet\"><p dir=\"ltr\" lang=\"en\">We don’t even know how to build this anymore. <a href=\"https://t.co/Y21FIwVIft\">https://t.co/Y21FIwVIft</a></p>&mdash; Matt Mullenweg (@photomatt) <a href=\"https://twitter.com/photomatt/status/1999769782279938531?ref_src=twsrc%5Etfw\">December 13, 2025</a></blockquote></div>\n</div></figure>\n\n\n\n<p>For <a href=\"https://www.apple.com/welcomescreen/ilife/iweb-3/\">the video to play on the webpage</a>, you have to visit in Safari.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 14 Dec 2025 05:57:55 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:39;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Matt: Winter Fun\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150836\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2025/12/winter-fun/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1017:\"<p>The colors here have now gone blue for winter, and snow has started, <a href=\"https://wordpress.org/plugins/snow-fall/\">thanks to the excellent Snow Fall plugin</a>. I also wanted to congratulate <a href=\"https://www.wealthfront.com/blog/wealthfront-ipo-public-company/\">Wealthfront on their IPO</a>. Many on their team have been friends or advisors over the years, from David Fortunato responding to my email about their WordPress blog being on an old version when they launched, to the amazing <a href=\"https://adamnash.blog/\">Adam Nash</a> who teaches <a href=\"https://cs007.blog/\">CS 007 Personal Finance for Engineers at Stanford</a>, and he now runs the awesome <a href=\"https://www.daffy.org/\">Daffy donor-advised tax fund startup</a>. I was an early customer, and even on their homepage as a testimonial in 2011, <a href=\"https://audrey.co/\">Audrey Capital</a> has been an investor since 2013 and if you <a href=\"https://wlth.fr/XArG0h\">sign up with this link we both get 5k extra managed for free</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 13 Dec 2025 04:43:27 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:40;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:39:\"Donncha: Make Photo Competitions Simple\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"https://odd.blog/?p=89592184\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://odd.blog/2025/12/12/make-photo-competitions-simple/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:10072:\"<p>Running a photography club competition used to mean juggling spreadsheets, chasing emails, and manually tallying votes. I built <a href=\"https://wordpress.org/plugins/photo-competition-manager/\">Photo Competition Manager</a> to change that.</p>\n\n\n\n<p>This free WordPress plugin handles everything your club needs: member management, secure uploads, flexible voting, and beautiful results displays.</p>\n\n\n\n<p>This will suit a photography club that uses WordPress for their website and that has a projector for their meetings. If you already run a photo league with projected images or prints but collect votes from your club members using pen and paper you&#8217;re the perfect candidate to try this plugin.</p>\n\n\n\n<p>This is the very first release of this plugin. It has been used a couple of times to run several test photo competitions and one monthly league competition. However, bugs happen. I would love if your photography club used this plugin but I will need feedback to improve it. Run a couple of test competitions first to get used to how it works.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Getting Started in Minutes</h3>\n\n\n\n<p>The setup wizard creates all the required pages automatically. Select the pages you need, click a button, and you&#8217;re ready to go.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592186 not-transparent\" height=\"679\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.47.34-1.avif\" width=\"762\" /></figure>\n</div>\n\n\n<p></p>\n\n\n\n<h3 class=\"wp-block-heading\">Manage Your Membership</h3>\n\n\n\n<p>The Members page is your central roster. Add members individually or bulk import from CSV. Assign grades, track status, and send magic-link upload invitations with a single click.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592188 not-transparent\" height=\"1041\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.47.05-1.avif\" width=\"1270\" /></figure>\n</div>\n\n\n<p>Each member gets a unique upload URL—no passwords to remember, no accounts to create. They click the link and upload.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Create and Track Competitions</h3>\n\n\n\n<p>The competitions dashboard shows a list of competitions, allowing you to edit them and send out upload emails to members. Only one competition may be active at a time, but a competition may have more than one category. </p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592190 not-transparent\" height=\"600\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.47.20-1.avif\" width=\"1278\" /></figure>\n</div>\n\n\n<p>Create competitions with custom categories (Colour, Mono, Projected, etc), grade divisions (Beginner, Intermediate, Advanced), and submission quotas. Each competition can have its own rules without affecting your defaults.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Watch Submissions Roll In</h3>\n\n\n\n<p>As members upload, the submissions page displays thumbnails of every entry. You&#8217;ll see who&#8217;s submitted, which categories are filling up, and whose photos are still missing.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592191 not-transparent\" height=\"580\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.48.00.avif\" width=\"1016\" /></figure>\n</div>\n\n\n<p></p>\n\n\n\n<h3 class=\"wp-block-heading\">A Frictionless Upload Experience</h3>\n\n\n\n<p>When members click their magic link, they land on a clean upload form. They select their category, choose their image, and submit. The progress banner shows upload status in real time.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592193 not-transparent\" height=\"982\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.43.06-1.avif\" width=\"876\" /></figure>\n</div>\n\n\n<p></p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592194 not-transparent\" height=\"145\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.43.34.avif\" width=\"821\" /></figure>\n</div>\n\n\n<p></p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592195 not-transparent\" height=\"739\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.43.54.avif\" width=\"873\" /></figure>\n</div>\n\n\n<p>The plugin handles validation automatically—file types, dimensions, and quota limits are all enforced before the image is accepted.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Complete Control Over Voting</h3>\n\n\n\n<p>The voting controls page is your competition command centre. From here you can:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Open and close voting for each category independently.</li>\n\n\n\n<li>Toggle the results display on or off.</li>\n\n\n\n<li>Enable slideshow mode for in-person club nights.</li>\n\n\n\n<li>Disable uploads once the submission deadline passes.</li>\n\n\n\n<li>Show a QR code for members to scan with their phones to vote.</li>\n</ul>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592196 not-transparent\" height=\"674\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.48.33.avif\" width=\"993\" /></figure>\n</div>\n\n\n<p></p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592198 not-transparent\" height=\"716\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.49.31-1.avif\" width=\"993\" /></figure>\n</div>\n\n\n<p>In the competition settings, you choose between token-based voting (unique links per member) or password-protected public voting. The voting controls page features a full-screen slideshow mode where members can vote together during meetings.</p>\n\n\n\n<p>On the night of the competition we do the following:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Close uploads and hide results.</li>\n\n\n\n<li>Show the slideshow with a 10 or 15-second delay as a preview.</li>\n\n\n\n<li>Display the QR code and make sure every member can scan it and open the voting page.</li>\n\n\n\n<li>Open voting and show the slideshow again.</li>\n\n\n\n<li>When everyone has voted, close voting.</li>\n\n\n\n<li>2 members of the club will then go through the images and offer a critique, using the slideshow again but in manual mode this time.</li>\n\n\n\n<li>Repeat for the next category.</li>\n\n\n\n<li>When all the voting is done, toggle the results page on and display the &#8220;top 3&#8221; results, and then the anonymous results page on the projector.</li>\n\n\n\n<li>Finally, an email is sent out to all members showing their score, ranking in their grade and the votes they received. Names are not attached to the votes for obvious reasons.<br /></li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Voting By Phone</h3>\n\n\n\n<p>Members can vote on the competition using their phones after they have scanned the QR code on the voting controls page.</p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-1 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-89592202 not-transparent\" height=\"1503\" src=\"https://odd.blog/files/2025/12/voting1.avif\" width=\"600\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-89592203 not-transparent\" height=\"661\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-18.31.11.avif\" width=\"413\" /></figure>\n</figure>\n\n\n\n<p></p>\n\n\n\n<h3 class=\"wp-block-heading\">Results That Make Sense</h3>\n\n\n\n<p>When voting closes, the results dashboard breaks down every score by member grade. See vote distributions, identify your winners, and export everything to CSV for your records.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592199 not-transparent\" height=\"1072\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-17.57.31.avif\" width=\"1180\" /></figure>\n</div>\n\n\n<p>The frontend includes a responsive top-3 podium display perfect for announcing winners, plus full results tables with filtering by grade and category.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592206 not-transparent\" height=\"1170\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-18.27.44-1.avif\" width=\"755\" /></figure>\n</div>\n\n\n<p></p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img alt=\"\" class=\"wp-image-89592207 not-transparent\" height=\"1150\" src=\"https://odd.blog/files/2025/12/Screenshot-2025-12-12-at-18.28.14.avif\" width=\"1192\" /></figure>\n</div>\n\n\n<p></p>\n\n\n\n<h3 class=\"wp-block-heading\">Built for Photography Clubs</h3>\n\n\n\n<p>Photo Competition Manager was built specifically for the way camera clubs actually run competitions:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Magic-link authentication</strong> means members don&#8217;t need WordPress accounts to upload.</li>\n\n\n\n<li><strong>Grade-based scoring</strong> supports clubs that split their membership by experience level.</li>\n\n\n\n<li><strong>Slideshow mode</strong> turns any screen into a projection-ready display.</li>\n\n\n\n<li><strong>CSV export</strong> keeps your archives intact.</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Get Started Free</h3>\n\n\n\n<p>Photo Competition Manager is free and GPL. Install it from the WordPress plugin directory or from the plugins page on your WordPress site in the usual way. Navigate to the Competitions menu to get started.</p>\n\n\n\n<p><a href=\"https://wordpress.org/plugins/photo-competition-manager/\">Download Photo Competition Manager</a></p>\n\n\n\n<p>The source code is available on GitHub if you want to contribute or customise:</p>\n\n\n\n<p><a href=\"https://github.com/donnchawp/photo-competition-manager\">View on GitHub</a></p>\n\n\n\n<p>Questions? Open an issue on GitHub or post in the WordPress support forum. I&#8217;d love to hear how your club uses it.</p>\n\n#Photography #photographyclub #WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 12 Dec 2025 19:11:05 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Donncha\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:41;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Matt: Aldeas\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150817\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"https://ma.tt/2025/12/aldeas/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1705:\"<p>Tonight was a lot of threads connecting for me. At <a href=\"https://automattic.space/\">Automattic&#8217;s Noho Space</a> we hosted an event for <a href=\"https://www.nytimes.com/2025/05/01/movies/martin-scorsese-pope-francis-documentary.html\">Martin Scorsese&#8217;s new documentary about Pope Francis, called Aldeas</a>. There was a point in my life when I wanted to become a priest, and I had been inspired by meeting a Franciscan seminary student. I took it very seriously and considered that as a path for my life, but some combination of jazz and girls made me realize that the priesthood was not my destiny.</p>\n\n\n\n<p>The jazz led to building websites for Houston jazz musicians, which led to coding, which led to WordPress, which after a lot of twists and turns led to <a href=\"https://ma.tt/2019/08/tumblr-the-day-after/\">Automattic acquiring Tumblr</a>. One of Tumblr&#8217;s <a href=\"https://en.wikipedia.org/wiki/Goncharov_(meme)\">greatest memes was Goncharov</a>, directed by Martin Scorsese. The only reason Automattic, as a distributed company, has an office in NYC is because of the Tumblr acquisition. The office is filled with art from Tumblr artists so I had the very surreal experience of talking after Martin Scorsese, who at 83 is sharp as a tack and a gifted speaker, a few feet away from a <a href=\"https://en.wikipedia.org/wiki/Goncharov_(meme)#/media/File:Goncharov-poster.png\">Goncharov poster</a> about how my Catholic upbringing led me down the path of starting WordPress, and how Pope Francis&#8217; life inspired the <a href=\"https://wordpress.org/news/2025/04/jubilee/\">WordPress Jubilee</a> and <a href=\"https://ma.tt/2025/04/reflecting/\">reflection</a>. Full circle.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 12 Dec 2025 05:45:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:42;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:94:\"Open Channels FM: WordPress 6.9: From Streamlined Content Creation to Powerful Developer Tools\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=113320\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"https://openchannels.fm/wordpress-6-9-from-streamlined-content-creation-to-powerful-developer-tools/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:232:\"In this episode, contributors Akshaya Rane, Birgit Pauli-Haack,  and Krupa Nanda discuss the collaborative process behind WordPress 6.9, highlighting features, performance upgrades, and emphasizing community involvement and testing.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 11 Dec 2025 10:40:12 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:43;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Matt: Year-end\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150805\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"https://ma.tt/2025/12/year-end/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:230:\"<p><a href=\"https://2025inreview.tumblr.com/\">Tumblr has a fun 2025 in review</a>, and if you&#8217;re a <a href=\"https://pocketcasts.com/\">Pocket Casts</a> user open the app to see all your stats for your listening this year.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 11 Dec 2025 03:40:56 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:44;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"WordPress.org blog: 2026 Global Partner Program Announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=19534\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:63:\"https://wordpress.org/news/2025/12/2026-global-partner-program/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:9308:\"<p>Become a driving force behind WordPress innovation by joining the Global Community Sponsorship Program: a comprehensive initiative that supports the events and people powering our open source mission. As a Global Sponsor, your organization gains meaningful visibility across the international WordPress ecosystem while helping to fund events that foster growth, collaboration, and community.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-19617\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/WordPress-Global-Partners-Program-2026-.jpg?resize=1024%2C576&#038;ssl=1\" width=\"1024\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Why Choose Global Sponsorship?</h2>\n\n\n\n<p>Instead of managing multiple individual sponsorships, this streamlined program consolidates your efforts into one efficient and impactful partnership.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Efficiency and Simplified Administration</h3>\n\n\n\n<p>Skip the complexity of coordinating invoice payments with numerous volunteer teams. Our centralized approach saves time and resources. In 2026, sponsors will benefit from:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>A dedicated Slack channel for direct communication with the WordPress Community Support team and Community Program Managers</li>\n\n\n\n<li>Monthly updates listing upcoming WordPress events, their current planning stages, and scheduled dates</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Expanded Reach and Impact</h3>\n\n\n\n<p>Your sponsorship amplifies your presence worldwide, ensuring consistent visibility across global WordPress community events.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Stability and Reliability</h3>\n\n\n\n<p>Your commitment strengthens locally organized events by providing predictable funding that supports venues, logistics, and growth.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Flexible Branding Options</h3>\n\n\n\n<p>Adapt across your portfolio—Global Sponsors can represent different brands at different events (subject to approval and advance notice).</p>\n\n\n\n<h3 class=\"wp-block-heading\">Program Benefits</h3>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td class=\"has-text-align-left\"></td><td class=\"has-text-align-center\"><strong>Global Leader</strong></td><td class=\"has-text-align-center\"><strong>Regional Powerhouse</strong></td><td class=\"has-text-align-center\"><strong>Community Builder</strong></td></tr><tr><td class=\"has-text-align-left\"><br /><br /><br /><br /><strong>Best for:<br /></strong></td><td class=\"has-text-align-center\">Established brands seeking global reach and year-round visibility.</td><td class=\"has-text-align-center\">Companies aiming for regional dominance and strong brand recognition.</td><td class=\"has-text-align-center\">Organizations supporting the next generation of WordPress education.</td></tr><tr><td class=\"has-text-align-left\">Sponsorship payable in full or through quarterly installments</td><td class=\"has-text-align-center\">$180,000</td><td class=\"has-text-align-center\">$110,000</td><td class=\"has-text-align-center\">$60,000</td></tr><tr><td class=\"has-text-align-left\">Top tier sponsorship benefits at all local <a href=\"https://central.wordcamp.org/\">WordCamp</a> events (excludes flagships) with priority access to claim a sponsor table at in-person <a href=\"https://events.wordpress.org/\">WordPress events</a></td><td class=\"has-text-align-center\"><img alt=\"✔\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" style=\"height: 1em;\" /></td><td class=\"has-text-align-center\"></td><td class=\"has-text-align-center\"></td></tr><tr><td class=\"has-text-align-left\">Option to feature multiple brands across events</td><td class=\"has-text-align-center\"><img alt=\"✔\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" style=\"height: 1em;\" /></td><td class=\"has-text-align-center\"></td><td class=\"has-text-align-center\"></td></tr><tr><td class=\"has-text-align-left\">Dedicated sponsor landing page</td><td class=\"has-text-align-center\"><img alt=\"✔\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" style=\"height: 1em;\" /></td><td class=\"has-text-align-center\"><img alt=\"✔\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" style=\"height: 1em;\" /></td><td class=\"has-text-align-center\"></td></tr><tr><td class=\"has-text-align-left\">Complimentary WordPress event tickets for your team</td><td class=\"has-text-align-center\"><img alt=\"✔\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" style=\"height: 1em;\" /></td><td class=\"has-text-align-center\"><img alt=\"✔\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" style=\"height: 1em;\" /></td><td class=\"has-text-align-center\"></td></tr><tr><td class=\"has-text-align-left\">Recognition across all <a href=\"https://events.wordpress.org/\">WordPress events</a></td><td class=\"has-text-align-center\"><img alt=\"✔\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" style=\"height: 1em;\" /></td><td class=\"has-text-align-center\"><img alt=\"✔\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" style=\"height: 1em;\" /></td><td class=\"has-text-align-center\"></td></tr><tr><td class=\"has-text-align-left\">Sponsor Spotlight post on WordPress.org/news featuring highlights from recent <a href=\"https://central.wordcamp.org/\">WordCamps</a></td><td class=\"has-text-align-center\">Quarterly</td><td class=\"has-text-align-center\">Annually</td><td class=\"has-text-align-center\"></td></tr><tr><td class=\"has-text-align-left\">Inclusion of your company logo in signage and materials for <a href=\"https://events.wordpress.org/campusconnect/\">WordPress Campus Connect</a> events</td><td class=\"has-text-align-center\">All signage &amp; materials for the year (digital and printed)</td><td class=\"has-text-align-center\">Signage &amp; materials for 5 events per year (printed only)</td><td class=\"has-text-align-center\">All signage &amp; materials for the year (digital and printed)</td></tr><tr><td class=\"has-text-align-left\">Opportunity to be featured in an exclusive digital binder for <a href=\"https://events.wordpress.org/campusconnect/\">WordPress Campus Connect</a> event organizers</td><td class=\"has-text-align-center\">Priority placement (logos &amp; text)</td><td class=\"has-text-align-center\">Feature listing (text only)</td><td class=\"has-text-align-center\">Feature listing (text only)</td></tr><tr><td class=\"has-text-align-left\">Regular recognition in <a href=\"https://make.wordpress.org/community/2025/11/03/monthly-education-buzz-report-october-2025/\">monthly education buzz report</a></td><td class=\"has-text-align-center\"></td><td class=\"has-text-align-center\"></td><td class=\"has-text-align-center\"><img alt=\"✔\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" style=\"height: 1em;\" /></td></tr></tbody></table></figure>\n\n\n\n<h2 class=\"wp-block-heading\">How Sponsorship Funds Are Used</h2>\n\n\n\n<p>Global Sponsorship funds directly support:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Local WordPress events worldwide (venue rental, catering, A/V, and more)</li>\n\n\n\n<li>Meetup.com license fees for over 671 WordPress Meetup groups globally</li>\n\n\n\n<li>Administrative costs like insurance, banking, and annual financial audits that ensure transparent operations</li>\n</ul>\n\n\n\n<p>Your partnership helps sustain the community that powers more than 43% of the web. Together, we can keep the WordPress project thriving and expanding for years to come.</p>\n\n\n\n<div class=\"wp-block-group has-off-white-2-background-color has-background is-layout-constrained wp-container-core-group-is-layout-d1b48064 wp-block-group-is-layout-constrained\">\n<p class=\"has-text-align-center\"><strong><strong>If your company is interested in joining the Global Sponsorship program or you would like to know more, please reach out</strong></strong>.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-a89b3969 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"mailto:support@wordcamp.org\">Contact WordPress Community Support</a></div>\n</div>\n\n\n\n<div class=\"wp-block-spacer\" style=\"height: 25px;\"></div>\n\n\n\n<p><em>Please see <a href=\"https://make.wordpress.org/community/handbook/wordcamp-organizer/planning-details/fundraising/global-community-sponsorship-for-event-organizers/#rules-for-sponsor-materials\">Rules for Sponsor Materials</a> for more details about terms of sponsorship. Please also see our <a href=\"https://make.wordpress.org/community/files/2024/12/Draft-of-2025-WordPress-Global-Community-Sponsorship-Agreement-Template-Google-Docs.pdf\" rel=\"noreferrer noopener\" target=\"_blank\">sample sponsorship agreement</a>.</em></p>\n</div>\n\n\n\n<p>If you’d like to go one step further, please consider <a href=\"https://wordpressfoundation.org/donate/\">donating directly to the WordPress Foundation</a>. We operate lean—every dollar goes toward keeping WordPress free, supporting education, and funding the community that makes the web a better place. In short, your donation helps us keep the lights on and the mission alive.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Dec 2025 17:16:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Harmony Romo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:45;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"WPTavern: #197 – Johanne Courtright on Enhancing Gutenberg: Agency-Driven Block Editor Innovations\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=201629\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:113:\"https://wptavern.com/podcast/197-johanne-courtright-on-enhancing-gutenberg-agency-driven-block-editor-innovations\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:54861:\"<details>Transcript<div>\n<p>[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p>Jukebox is a podcast which is dedicated to all things WordPress. The people, the events, the plugins, the blocks, the themes, and in this case, enhancing Gutenberg with agency driven block editor innovations.</p>\n\n\n\n<p>If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p>If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. . Head to wptavern.com/contact/jukebox, and use the form there.</p>\n\n\n\n<p>So on the podcast today we have Johanne Courtright. Johanne started working with WordPress back in 2011, moving over from a background in marketing agencies, Dreamweaver and Static HTML sites. Over the years, she&#8217;s become a skill developer, focusing on extending WordPress through custom queries, forms, integrations with APIs, and increasingly harnessing the power of the block editor and React.</p>\n\n\n\n<p>Johanne talks about her journey from the classic world of agency WordPress development to embracing Gutenberg, and the challenges and wins along the way. She shares her experience in building custom blocks, and enhancing existing ones to better serve agencies. Things like improving break points, color palettes, responsive designs, and navigation, all of which aren&#8217;t offered in Core yet. These features come together in her growing open source project Groundworx.</p>\n\n\n\n<p>We talk about the shifting landscape from classic themes to block-based themes, and why even in 2025, a lot of agencies and users are still hesitant to make the leap fully. Johanne explains where the block editor falls short for her use, and how Groundworx aims to plug these perceived gaps with a foundation of flexible, performant, agency focus blocks and templates.</p>\n\n\n\n<p>You will hear about her approach to building modular themes with theme.json, the realities of client work and scope creep, and how the 80 20 rule shapes what belongs in Core, and what&#8217;s best handled by plugins.</p>\n\n\n\n<p>We also get into the challenge of discovery in the WordPress plugin ecosystem, her wishlist for block editor improvements, and her take on the future of block-based businesses in WordPress.</p>\n\n\n\n<p>Whether you&#8217;re a developer eager to modernize your workflow, or just curious about extending Gutenberg for real world use, this episode is for you.</p>\n\n\n\n<p>If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p>And so without further delay, I bring you Johanne Courtright.</p>\n\n\n\n<p>I am joined on the podcast by Johanne Courtright. Hello, Johanne.</p>\n\n\n\n<p>[00:03:21] <strong>Johanne Courtright:</strong> Hi. Nice to be here.</p>\n\n\n\n<p>[00:03:22] <strong>Nathan Wrigley:</strong> Yeah, very nice to have you with us. I put a tweet out not that long ago, seeing if anybody wanted to come on the WP Tavern Jukebox podcast, and Johanne was very kind and reached out to me. And we had a little bit of toing and froing. Not a lot, but a little bit. And I thought that the topic of conversation that she suggested was extremely curious.</p>\n\n\n\n<p>As you&#8217;ll discover in a moment, Johanne has been working hard trying to make the block editor, well, I&#8217;m going to use the word improved. Trying to add things to the block editor to make it more usable.</p>\n\n\n\n<p>That conversation though, probably would benefit from us knowing exactly who you are, and what your background is. Maybe if we stick to the WordPress bits and pieces, but would you mind just giving us a little biography? Tell us a bit about you.</p>\n\n\n\n<p>[00:04:00] <strong>Johanne Courtright:</strong> Sure. I got into WordPress in 2011, working for a marketing agency. It solved a big problem at the time coming from Dreamweaver, HTML static pages. My writing to that was a lot of convincing, but it was a very welcome change. WordPress made a huge impact on a lot of agencies.</p>\n\n\n\n<p>And so we used it for, primarily for home builders, and it was great. Discovered Advanced Custom Fields, tapped into that. Custom post types. It was a lot of fun for many years and I&#8217;ve worked for other agencies after that too, and my specialty has always been around extending as far as I can. Custom queries and forms, tapping into CRM and with APIs and all sorts of things. Anything that can be done with WordPress I was doing it, pretty much.</p>\n\n\n\n<p>[00:04:55] <strong>Nathan Wrigley:</strong> Are you self-taught then, or have you learned on the job? Or did you go through like a university program or something like that?</p>\n\n\n\n<p>[00:05:00] <strong>Johanne Courtright:</strong> Just learned on the job. Just looking for solution, and WordPress felt like it was a great fit. A lot of support online, a lot of documentation, just a lot of people providing enough documentation to be able to explore was very helpful. And there was Joomla and Drupal that was also contenders, but I didn&#8217;t like Drupal&#8217;s interface, and I wasn&#8217;t a fan of how unstable Joomla was from updating versions to versions. So for me, it was a pretty fast decision to go with WordPress.</p>\n\n\n\n<p>[00:05:35] <strong>Nathan Wrigley:</strong> I think WordPress is a really great thing to hang your coat on if you are learning, because there&#8217;s so much, like you said, documentation. So much of it is prebuilt, so you can just download a version of WordPress and dig in basically, and see how somebody else over many years, in the case of WordPress, 22 years, how that has been built.</p>\n\n\n\n<p>Whereas I always found when I was digging in, so this is prior to me using any CMS, I had those PHP books, paper books, where you try to learn. And you&#8217;d always learn from nothing and you&#8217;d have to start building up and anything that you did wrong, you kind of really didn&#8217;t know what was going on.</p>\n\n\n\n<p>And so I quickly moved into the CMS space, and probably a little bit like you, WordPress was able to scaffold my learning. And quite a lot of the things that I thought I wouldn&#8217;t be interested in, I could skip over. I don&#8217;t know, things like permissions and stuff. WordPress already did that, so I didn&#8217;t really have to worry about how all of that was taken care of. So it enabled me to learn more quickly. And then of course, there&#8217;s the whole community behind it, and knowledge bases and articles and that whole thing. So I well understand your story.</p>\n\n\n\n<p>However, you&#8217;ve gone in a much more developer direction, I think, than I ever did. Looking at the bits and pieces that you are doing now, I think it&#8217;s fair to say that you have become a really competent developer, not just with things like PHP and JavaScript, but also I think more recently with things like React as well. How are you finding all of that, the new React based WordPress? Is it still maintaining the interest or are you banging your head on the wall a lot?</p>\n\n\n\n<p>[00:06:58] <strong>Johanne Courtright:</strong> I started Gutenberg, I started to use it pretty much around the time it came out. I had a bit of a struggle because I had to learn React for it. I didn&#8217;t want to be left behind, so I really tried hard, took a course online to accelerate a bit of my learning. And then I faced a time where it was just too much work to be done.</p>\n\n\n\n<p>But the last agency I worked at, I started I think like four or five years ago, they were open. They wanted to tackle it. And so we&#8217;re a team of three to start, and we made like a core foundation of blocks that we needed over time, building off projects and versions.</p>\n\n\n\n<p>And so it was a lot of fun, but in the same time we were still stuck in the old world with ACF for some of it. And I wasn&#8217;t quite pleased on some of it, but I understand sometimes like the budget, because I&#8217;m allowed to be fully a hundred percent Gutenberg. So when I decided to start something on my own to solve those things, I went a hundred percent Gutenberg, Interactivity API, no jQuery as much as possible. I decided to dive in completely, a hundred percent, because I believed in it. I knew how to solve those issues.</p>\n\n\n\n<p>[00:08:11] <strong>Nathan Wrigley:</strong> Yeah, all of those things that you&#8217;ve mentioned, you know, things like custom fields and things like that, they&#8217;re really curious, aren&#8217;t they? I mean, they&#8217;re really interesting stuff that you can do there, and it&#8217;s very much time saving, but it does feel like in the future there are utterly different possibilities there. And blocks, and all of the different bits and pieces that we&#8217;ll get into that you are working on, afford the chance to build custom solutions for every single project, without necessarily relying on downloading a plugin. You know, writing a bit of code, which will achieve a bit of functionality for this particular block or that particular block.</p>\n\n\n\n<p>However, all of that stuff being said, and the sort of rainbow version that we&#8217;ve painted of Gutenberg, it&#8217;s pretty obvious to me that during the last few years, there must be parts of the block editor that you&#8217;ve found to be lacking. Because as we&#8217;re going to discover, you&#8217;ve got a project called Groundworx, which is an endeavor in lots of different ways to bring features into the block editor which you feel probably, I&#8217;m guessing you feel, should have been shipped a long time ago.</p>\n\n\n\n<p>And I think it&#8217;s fair to say that your endeavor here is not to create a new suite of blocks, which you would download and replace core blocks. You are trying to enhance the paragraph block or the whatever block it may be. So you&#8217;re taking the core block, adding functionality into it. Have I got that right? Is that the endeavor?</p>\n\n\n\n<p>[00:09:34] <strong>Johanne Courtright:</strong> I have some extra blocks, but I did enhance quite a bit of what was already there, but not too much that it would interfere if they were to ever support. I mean, I have to be cautious on what I&#8217;m adding. But essentially, if you take WordPress as is, it&#8217;s good enough for somebody who&#8217;s starting, but it&#8217;s not good enough for an agency.</p>\n\n\n\n<p>[00:09:57] <strong>Nathan Wrigley:</strong> What are the bits that you think are missing? And honestly, feel free to just dig deep here. I know for me what I found lacking, but it only maps to the things that I have had to do. But I&#8217;m curious what a different person having worked for agencies and built a suite of blocks, what are the, I don&#8217;t know, four, five different things that you really feel are missing?</p>\n\n\n\n<p>[00:10:15] <strong>Johanne Courtright:</strong> You have to be pixel perfect with agencies, and they work with break points, and in containers and whatnot. And so you have to really kind of like stretch it further. And you have to also provide user experience efficiencies, for example, colour palettes and things like that. So you have to make it easier. So having presets of colours that already predetermined based on their branding, is ideal. So they can choose those presets, it already applies all the colours and your set. And then they can still override each components, which is amazing. That was something very important.</p>\n\n\n\n<p>So efficiencies and ease of use was great. So a combination of some custom blocks, but a lot of pre-made templates that you can make for them, and colour palettes. So the more you embrace Gutenberg, the more you can make it happen. But if you have those solutions that are not quite fully Gutenberg, it becomes a little bit complex because you&#8217;re fighting Gutenberg.</p>\n\n\n\n<p>[00:11:13] <strong>Nathan Wrigley:</strong> Did you build your suite of blocks? And we&#8217;ll get into what that means in a minute, and we can highlight the different bits and pieces that you&#8217;ve got. But did you build that out of frustration or were there, I don&#8217;t know, particular things that a particular project needed that was pretty edge case that you thought you&#8217;d build? Or is this more a case of, okay, everybody needs these things, it&#8217;s curious that they&#8217;re missing in Core? What&#8217;s the approach? Is it kind of edge case stuff or is it more, everybody could benefit from these?</p>\n\n\n\n<p>[00:11:42] <strong>Johanne Courtright:</strong> It&#8217;s a little bit of everything. Most of the time, agencies would need those extra features I brought in. The problem is, I didn&#8217;t want to overwhelm normal users as well with so many options. And I think that&#8217;s where Gutenberg is shining essentially.</p>\n\n\n\n<p>The padding system, for example. It&#8217;s got increments, but it doesn&#8217;t have an overwhelming amount of like, this is the padding for this break point, this is the padding for this break point. But you can still tap into it by using clamp on your padding to adjust based on your screen resolution. So you can solve that problem without having to specify all those extra padding for each break point.</p>\n\n\n\n<p>So there&#8217;s a lot of different ways to set up your theme.json to compensate for the lack of extra features per breakpoint. And that&#8217;s what I&#8217;ve been doing. And my goal is to set up enough blocks and provide, I&#8217;ll have a theme.json that I want to share, so it&#8217;ll be easy for people to have a starting theme to start with. And I&#8217;m planning to release that for free. I was just, there&#8217;s a lot to be done and provide documentation. There&#8217;s just a lot. It&#8217;s hard to get everything done fast.</p>\n\n\n\n<p>[00:12:57] <strong>Nathan Wrigley:</strong> Yeah, no kidding. I mean, have you built your own themes then from the ground up, or do you tend to rely on, I don&#8217;t know, a default theme and then modify that?</p>\n\n\n\n<p>[00:13:06] <strong>Johanne Courtright:</strong> I actually prefer to use my own theme. In fact, coming from the old world, you would put everything in a theme. You would put just all your functionality. And then you learn over time that it&#8217;s probably better to have a plugin, but then you still had the crossover of the two dependencies. You have to be cautious to not crash your site if one wasn&#8217;t, like if you switched a theme or if you switch a plugin.</p>\n\n\n\n<p>And then Gutenberg made it easier to create that separation because you can set up, if you set up your theme properly, you can have essentially 90% of your theme set up in a way where it&#8217;s accent one for colour, accent two for colour base, and contrast. So if you label your things, your keys properly, all you have to do is change the values. Don&#8217;t change the key names. And just create labels that are meaningful. You can create another theme super easy from that initial theme by just changing those labels and those values, and leave the keys alone. Sure, you&#8217;ll have probably more colours on certain other themes, but your foundation will help you get there faster.</p>\n\n\n\n<p>[00:14:19] <strong>Nathan Wrigley:</strong> I know that many years ago when Full Site Editing, as it was called back then dropped, and so block themes became a thing. I know that there was a hope that it would, over a fairly short period of time, that it would replace what we&#8217;re now calling Classic Themes. There was this period of time where, you know, both were still massively in development. And I think the hope was that over time, Classic Themes would become more obsolete, and then block-based themes would become the default.</p>\n\n\n\n<p>It feels from where I&#8217;m standing now, so we&#8217;re recording this in December, 2025, it feels as if that kind of hasn&#8217;t really happened. That promise is still, we&#8217;re still somewhere in limbo. There&#8217;s a few people out there in the WordPress space who are promoting Full Site Editing and all of the things that that can do, but I also feel there&#8217;s a lot of people who are not willing to make that leap.</p>\n\n\n\n<p>And I guess part of the problem maybe is that it&#8217;s easy for somebody like you because you&#8217;re in it day in, day out. You know where every menu is. You know where to put the mouse to achieve the exact thing you want at the exact moment that you want. But I feel that for a novice user, maybe somebody who&#8217;s got the job of, I don&#8217;t know, finishing off a website or somebody who&#8217;s got the job of just tweaking a website once it&#8217;s been handed over, I think it&#8217;s really hard, and a lot of the interface is kind of counterintuitive.</p>\n\n\n\n<p>And when you stand over the shoulder, as I have done, of people who&#8217;ve never used WordPress before, and you watch them, you see them flailing around trying to figure out how it works, and you see the constant butting up against a UX problem. I don&#8217;t know when that moment&#8217;s going to be, where everything is all tied off and perfect, but it doesn&#8217;t seem like in the year 2025, the few weeks that we&#8217;ve got left, or anytime soon in 2026, as if the Classic Themes are going to go away.</p>\n\n\n\n<p>And I don&#8217;t know if that concerns you at all, because obviously you&#8217;ve really invested in all these blocks and theming and all of that kind of stuff. Does it bother you that this is still a problem that we haven&#8217;t solved?</p>\n\n\n\n<p>[00:16:18] <strong>Johanne Courtright:</strong> I think what&#8217;s out there right now, the third party, what they&#8217;re doing, I mean, they&#8217;re solving some issues, but they&#8217;re adding a whole new platform on another existing platform, and that&#8217;s why I don&#8217;t choose those solutions. I prefer embracing the Core vision and try to expand what&#8217;s already there.</p>\n\n\n\n<p>One of my struggles I have is that, let&#8217;s just pick Elementor. You have a lot of great options. I mean, for somebody who knows what they&#8217;re doing, it does a lot, but it also comes with a lot of extra bloat of divs and CSS that&#8217;s not quite built how I would&#8217;ve done it. You have to fight the styling. And WordPress does it so different now. With Gutenberg, it&#8217;s the opposite. It does very little, and it allows you to override all the classes. The way it&#8217;s built, it&#8217;s allowing you to override easily without having to use the important on the styling to override it.</p>\n\n\n\n<p>And I think that&#8217;s a major change of how you think, and how you approach theming in general. This is the way. This is the way how it should be done. And once I stopped fighting how the new way was, and understanding where they were heading with that, something clicked and it just like, yes, this is what I want, this is what I want. And I made that call that I&#8217;m not going back.</p>\n\n\n\n<p>No normal users want to touch Divi or Elementor. Somebody who doesn&#8217;t have the knowledge of basic CSS even, they don&#8217;t want to touch that. It&#8217;s overwhelming. They don&#8217;t know how to touch it. And in fact, they&#8217;re scared. And when you present them with Gutenberg, you give them an hour training over Zoom session, they are in love with it. They make edits themselves. They&#8217;re just happy. They rarely come back with more questions. They just know how to use it.</p>\n\n\n\n<p>[00:18:12] <strong>Nathan Wrigley:</strong> I think we&#8217;re fast approaching a period in WordPress when a lot of the admin UI is about to change. So there&#8217;s a lot of foundational work being put in at the moment to really modify it. So maybe some of that dissonance that users might face in the near future will go away. And maybe those kind of block-based themes, and Gutenberg use in general will spike. There certainly seems to be a lot of work being done in that regard anyway.</p>\n\n\n\n<p>Let&#8217;s just move on to some of the bits and pieces that you have been doing though. Because obviously there must be, well, dissatisfaction is the wrong word, but there&#8217;s obviously bits of the block editor where you feel that work could have been done differently.</p>\n\n\n\n<p>And so I&#8217;m going to point people in the direction of your work. So if you go to groundworx.dev, and worx is spelt with an X at the end. So it&#8217;s the word ground, and then WOR and then the letter X, dot dev. If you go there, you&#8217;ll be able to find the product menu. And if you hover over the product menu, you&#8217;ll be able to see a bunch of things called Groundworx core and things like that, Groundworx navigation.</p>\n\n\n\n<p>And I want to dwell on Groundworx core. So this is your endeavor to improve the blocks that WordPress offers, and offer some new ones and modifications to existing ones. Tell us what the philosophy behind this is then.</p>\n\n\n\n<p>[00:19:29] <strong>Johanne Courtright:</strong> So some of the more fun blocks where they have like animation and all that are custom blocks. But they&#8217;re flexible in the way they&#8217;re easy to set up, intuitive. But I think for me, offering the capability to someone who wants those type of things that are not offered, it&#8217;s not necessarily a frustration for those because it&#8217;s just in addition to, it&#8217;s nice to have, it&#8217;s not a must have, essentially. They&#8217;re really nice, already pre-made blocks with the inner blocks and content that you can change.</p>\n\n\n\n<p>One of the ones that are, I think, lacking, I know we have the accordion block that came in recently. Mine is different, where I can have an accordion, but I can also have a tab. A tab that can turn into an accordion based on a specific break point. So it won&#8217;t go from accordion, to tab, to accordion, back to tab at several different break points, but it will have one point where you&#8217;ll tell it to break.</p>\n\n\n\n<p>So you can have a tab that can turn into accordion, which is nice to have because, I mean, tabs are not very friendly, but you still want them. You still want them. They&#8217;re useful visually at larger desktops, but you don&#8217;t necessarily want to deal with tabs at a mobile, unless they&#8217;re very small text and very few. So you need something to shift that. And you want to keep consistency. With accordions that you already have, so it looks good altogether. So that&#8217;s what I created. I have an accordion, and a tab, but the tab can fall into an accordion as well. And when they do fall into an accordion, they all look consistent and the same.</p>\n\n\n\n<p>[00:21:13] <strong>Nathan Wrigley:</strong> So currently if you, I&#8217;ll put the link in the show notes by the way. So if you go to wptavern.com and you search for the episode with Johanne in, then you&#8217;ll find all of the show notes. It&#8217;s probably easier than me reading out URLs and what have you.</p>\n\n\n\n<p>Your kind of block suite falls into two main categories, as far as I&#8217;m concerned anyway. So you&#8217;ve got your purpose built 11 kind of custom blocks where you are doing something that Core didn&#8217;t do. Although we might discuss how Core might tackle some of those things in the near future.</p>\n\n\n\n<p>But then also, the bit that I find really interesting is the whole section where you&#8217;ve got extension to Core blocks. So as an example, I&#8217;ll give you some examples of things which, dear listener, if you don&#8217;t use Gutenberg, you may be surprised to know that the block editor currently does not do these things.</p>\n\n\n\n<p>So for example, you have the capacity to reverse the order of a stack, which is really nice. So you might want to just, I don&#8217;t know, put an image above something on a desktop. And then on mobile, you might just want to flip that, or you might just want to flip it because you are doing, I don&#8217;t know, copy and pasting rows, but you want the image left, image right, image left, image right, that kind of thing.</p>\n\n\n\n<p>You&#8217;ve also added in break points for certain widths. So for example, a tablet break point might be in there. You&#8217;ve got a full height sticky for the group block, which is nice and interesting as well. Three breakpoints for WordPress headings and paragraphs. That&#8217;s nice. So you could, I don&#8217;t know, change the font size or something like that depending on what you&#8217;re looking at.</p>\n\n\n\n<p>Column counts. So you&#8217;ve got the ability to have different breakpoints in the Core list block as well.</p>\n\n\n\n<p>You&#8217;ve got a whole thing about performance optimisation for the video block, and then you&#8217;ve got a responsive setting for any break point that you may set. I probably butchered all of that, but you get the idea. You&#8217;ve got a ton of stuff that you&#8217;ve built on top of Core WordPress blocks.</p>\n\n\n\n<p>Why do you, because I mean, all of that I guess is given away to everybody, but there&#8217;s got to be an expectation, I suppose, that some of this stuff will ship in Core. Does that bit worry you? Does it worry you that you put in all this hard work and then somebody maybe in the Core project thinks, oh, that&#8217;s a good idea, let&#8217;s add that to the roadmap and what have you.</p>\n\n\n\n<p>[00:23:16] <strong>Johanne Courtright:</strong> I mean, it&#8217;s always a worry when you release something for WordPress because everything is GPL, but it&#8217;s just part of the ecosystem. I mean, I reverse engineered their blocks to learn what I know now.</p>\n\n\n\n<p>[00:23:27] <strong>Nathan Wrigley:</strong> Yeah, that&#8217;s a good point. Yeah.</p>\n\n\n\n<p>[00:23:28] <strong>Johanne Courtright:</strong> And if they think it&#8217;s great idea then, you know, as long as they give me credit, I guess it&#8217;s fine.</p>\n\n\n\n<p>But I say, not everyone will need break points. I mean, this is really more like, I&#8217;d say agency type things that usually you want those things, those features. They&#8217;re nice to have, but break points are not necessarily, I have to have it kind of thing if you are just a normal user. It&#8217;s more, if you want fine tuning for, like if you&#8217;re a designer and you really want those fine tunings, then they&#8217;re there.</p>\n\n\n\n<p>[00:24:03] <strong>Nathan Wrigley:</strong> Does it kind of surprise you though that we are now, oh goodness knows how many years we&#8217;re into the Gutenberg project, but it&#8217;s many, many years. It&#8217;s more than you can count on one hand. Does it surprise you that this stuff is still missing? That somebody like you needs to build this functionality and, well, needs is maybe the wrong word, but desires to build this functionality. Does it surprise you that this kind of thing wasn&#8217;t in it when it shipped, that a layout system with all the break points taken care of and all of that completely customisable, does it still shock you that that isn&#8217;t there?</p>\n\n\n\n<p>[00:24:34] <strong>Johanne Courtright:</strong> I have not done a whole lot of research, but based on what I&#8217;ve read so far is there was no intention to support it. So that&#8217;s why I decided to do it because I was like, I&#8217;m not going to wait for them to do it because they&#8217;re not going to do it.</p>\n\n\n\n<p>[00:24:50] <strong>Nathan Wrigley:</strong> Yeah. So it was never something that was intended that was missing. It was just, it was never, literally never intended. So somebody needed to ship it. It&#8217;s kind of like that WordPress 80 20 rule. That&#8217;s the other curious thing about WordPress usage. Somebody like you and somebody like me who is constantly in there and fiddling the entire time, you kind of have this expectation that a lot of this stuff, oh, everybody would need this because I need it.</p>\n\n\n\n<p>But the reality is, I guess most people are just logging in, changing a piece of text, maybe uploading an image, writing a blog post, clicking publish, and they&#8217;re done. And they&#8217;re relying on their agencies who&#8217;ve got the CSS, JavaScript, all of that React expertise that can build all of the different bits and pieces for them. So maybe it&#8217;s just me obsessing about these things because I&#8217;m in there all the time and I can see how they&#8217;re missing.</p>\n\n\n\n<p>[00:25:36] <strong>Johanne Courtright:</strong> I think the way I build themes these days is like extremely light. It&#8217;s like, there&#8217;s a theme.json, there&#8217;s very little CSS and very, very little JavaScript. Everything is moved towards plugins. It&#8217;s really meant for colours, font types, branding type things. I have very little things in my themes these days because I believe that somebody who has a website and tomorrow they want a different theme, even for Christmas, and they decide, oh, I want a Christmas theme, should be able to do it easily by just swapping the theme.</p>\n\n\n\n<p>[00:26:13] <strong>Nathan Wrigley:</strong> Clicking a button and it should all work, yeah.</p>\n\n\n\n<p>[00:26:14] <strong>Johanne Courtright:</strong> Click a button, and all of a sudden it&#8217;s the new font, it&#8217;s the new palette colour, and it just works with minimal effort to just change anything or tweak anything. That&#8217;s how I see it. You shouldn&#8217;t have things that are baked in your theme where if you change your theme, now all of a sudden it&#8217;s not available for that theme. Don&#8217;t lock your clients into essentially a theme with features, and then they&#8217;re stuck with your theme.</p>\n\n\n\n<p>[00:26:45] <strong>Nathan Wrigley:</strong> Okay, so that&#8217;s an interesting way of kind of spinning my question around in a sense. That whole thing that we have with clients where we have scope creep, you offer something, they agree to it, and then there&#8217;s this whole thing after you&#8217;ve built what they wanted, where they say, oh, but can we have, and then can we have, and what about this? We&#8217;ve got this idea as well. But that&#8217;s not the intention. The project was what we said it was going to be.</p>\n\n\n\n<p>And so in a sense, the WordPress project is a little bit like that. You know, it&#8217;s not trying to be every feature for every human being who ever thought a thing could be achieved. It&#8217;s more, here&#8217;s the foundational stuff, and if you really want those things, well, either build it yourself or go and find somebody who has built that for you.</p>\n\n\n\n<p>That kind of makes a lot of sense, doesn&#8217;t it? You know, if you&#8217;ve got this foundational platform, and I know the 80 20 rule, like I said, applies within WordPress. If 80% of the people need it, then it comes onto the scope of Core, and if it doesn&#8217;t reach that then it really doesn&#8217;t belong in Core. That&#8217;s kind of interesting because that reframes the whole thing and makes what you are saying true.</p>\n\n\n\n<p>Most of the things that you&#8217;ve got, that you&#8217;ve built on top of Core, and again, I&#8217;ll direct people to the URL on the WP Tavern website. They probably aren&#8217;t for 80% of the people, they probably are for the 20%, the people like you, the developers, the designers who are building websites. The inexperienced people, the 80%, maybe they don&#8217;t need this stuff. That&#8217;s an interesting reframing of it.</p>\n\n\n\n<p>[00:28:07] <strong>Johanne Courtright:</strong> Yeah, most people will probably be satisfied with just the basic theme that comes with WordPress. It&#8217;s got enough patterns at this point to have a good starting foundation. We need to get away from overbuilding our blocks in such a way where they&#8217;re rigid, this is the only thing it can do.</p>\n\n\n\n<p>So when I build my blocks, I build in such a way the HTML can be moved around with grid system CSS, where I can move things because I built it in such a way that it&#8217;s very flexible. So all you have to do after that is just you create like some styling to accommodate that other different behavior that you want.</p>\n\n\n\n<p>[00:28:51] <strong>Nathan Wrigley:</strong> So we&#8217;ve spoken just then about the bits and pieces that, you&#8217;ve extended WordPress Core and we described all of those. But there&#8217;s obviously bits that you felt were entirely missing that you thought might be useful to have. As I said a moment ago, some of these maybe are things that, I don&#8217;t know, maybe you&#8217;ll drop in the near future, or perhaps you&#8217;ll tweak in different ways because you did say that your accordion block behaves differently. But I know that the accordion block is coming to Core and what have you.</p>\n\n\n\n<p>But you&#8217;ve got things like an Accordion Block, you&#8217;ve got an Accordion Panel Block, a Tabs Block, Tabs Panel Block, Media Section Block, Media Content Split Block, that&#8217;s interesting. Card block, Card Reveal Block and many others. This is, I guess, is this you sort of dogfooding projects that you&#8217;ve had in the past where a client has wanted a particular thing and you&#8217;ve thought, oh yeah, I&#8217;ve now built that, let&#8217;s see if we can sort of make it more generic and add it into your suite of blocks?</p>\n\n\n\n<p>[00:29:43] <strong>Johanne Courtright:</strong> Those are pretty much blocks that keeps happening and being reused over and over and over. And they kind of become your basic foundation, if that makes sense. And they usually solve 90%, 95% of what you need for a site is essentially what&#8217;s part of the Core, is how I solved it. Another one that I solved that is very similar to what WordPress does was the Core Navigation.</p>\n\n\n\n<p>[00:30:09] <strong>Nathan Wrigley:</strong> Oh, you&#8217;ve got a whole other thing there, haven&#8217;t you? Yeah, that&#8217;s interesting.</p>\n\n\n\n<p>[00:30:12] <strong>Johanne Courtright:</strong> Yeah, this one is completely free, so I mean, my navigation falls very similarly what WordPress does, where I have a custom post type, I have blocks in it, and essentially it will use those menus that I can reuse in different parts of navigations. And the major difference is that WordPress is only this big modal and then you have very little customisation. It can go left or right, I think center.</p>\n\n\n\n<p>[00:30:43] <strong>Nathan Wrigley:</strong> That&#8217;s more or less it really, isn&#8217;t it?</p>\n\n\n\n<p>[00:30:45] <strong>Johanne Courtright:</strong> Yes. And it is annoying because if you choose left or right, well, it also affects your desktop versus modal, I didn&#8217;t like that. But I did like the idea of having the blocks sitting into a custom post type. So mine in that way does that too. But I didn&#8217;t want to interfere with what WordPress had done, so I created my own custom post type for it. But I&#8217;m still following the same principle where I have my blocks sitting in that custom post types be shared so I can reuse them.</p>\n\n\n\n<p>[00:31:18] <strong>Nathan Wrigley:</strong> So you can use Core navigation blocks containing the pages and the posts and things like that. How do you build them up?</p>\n\n\n\n<p>[00:31:25] <strong>Johanne Courtright:</strong> Well, I essentially copied over the link and the sub menu and I brought over some of their features, because I did like how they were, but I changed the HTML in it and what it&#8217;s capable of doing. Had a couple different things. That allowed me the flexibility to create accordions, and all sorts of different things without having to worry about having, you know how some sites will have a mobile menu, but they&#8217;ll have the same menu for the desktop, but it&#8217;s like a clone, but you don&#8217;t see it. I didn&#8217;t want that. Everything had to be done from the same HTML structure, and all it had to do is just essentially fall back gracefully into that other mode. And what was important also for me was that it was all Interactivity API.</p>\n\n\n\n<p>[00:32:20] <strong>Nathan Wrigley:</strong> Oh, interesting. Okay, you&#8217;ve been leveraging that.</p>\n\n\n\n<p>[00:32:23] <strong>Johanne Courtright:</strong> Yeah. So they&#8217;re all leveraging that. I was inspired also by Gutenberg Times website to do the vertical menu.</p>\n\n\n\n<p>[00:32:31] <strong>Nathan Wrigley:</strong> Yes. Yeah, they&#8217;ve got the, I don&#8217;t know which theme they&#8217;re using, but that I think was a default theme. Was it 2020?</p>\n\n\n\n<p>[00:32:37] <strong>Johanne Courtright:</strong> I was like, this is different. I want one like that. So I did support it too.</p>\n\n\n\n<p>[00:32:41] <strong>Nathan Wrigley:</strong> Yeah, I see that. So on your navigation block, one of the options is to have this kind of full height column, which you can invoke and the menu, I guess slides out, but it then collapses back into that full size column. Have you had much feedback on that? Because it, I always worry that that&#8217;s going to consume quite a bit of the real estate when it&#8217;s not being invoked. Whereas, you know, a little hamburger icon, which is sitting at the top of the screen is obviously not consuming anything once you&#8217;ve scrolled past the navigation menu. Does it stay there all the time? If you&#8217;re not using the menu at that moment, does it live there all the time or, how does it work?</p>\n\n\n\n<p>[00:33:14] <strong>Johanne Courtright:</strong> The bar stays there all the time. It&#8217;s up to you to add links that are useful in terms of what you&#8217;re doing. But, yes, it does stay there. It takes a little bit of the space, but it&#8217;s fine. You can choose also at what break point it will be sitting at the top instead.</p>\n\n\n\n<p>[00:33:34] <strong>Nathan Wrigley:</strong> Oh, I see. Got it. Right. There is an option to remove it. Yeah, yeah, yeah. Okay.</p>\n\n\n\n<p>[00:33:38] <strong>Johanne Courtright:</strong> Yeah. So you&#8217;re not, let&#8217;s just say you wanted to stop doing that at laptop or something, or tablet, then you just choose the option and it will just break to the other one at the top instead.</p>\n\n\n\n<p>[00:33:49] <strong>Nathan Wrigley:</strong> Okay. And you&#8217;ve built a suite of blocks, so six at the moment that work in concert together to build that. So you&#8217;ve got the Navigation Block, which I&#8217;m guessing is kind of the wrapper for that, I&#8217;m not sure. But then you&#8217;ve got the Branding Block, which I presume holds logos and things like that. The Menu Block, which is the responsive bit where you can display stack menu items and things like that. Sub Menus, which I guess allows you to create those accordions where there&#8217;s a parent item, but things hidden underneath. A Link Block where you can just add a single thing, which I guess isn&#8217;t inside any other navigation anywhere. And then a spacer block, just something to create a bit of breathing room to separate one thing from another. And those six things, you just build in your custom post type, and once you&#8217;ve built them there, you can then invoke it and construct it entirely in the block editor.</p>\n\n\n\n<p>You see this kind of stuff is really cool and really clever. Just the idea that you can build that in a, in this GUI, the block editor. Build it, style it, do all of the bits and pieces that you need to make it look nice inside the settings panel. It&#8217;s so great. The promise of Gutenberg delivered, really. This is the kind of stuff that it was always supposed to do, but people only seem to be getting to it now.</p>\n\n\n\n<p>[00:34:57] <strong>Johanne Courtright:</strong> You know, you did ask me a few times if there was a feature I wish was in WordPress, and I do have one right now. Theme.json, you can specify specific colours for your buttons and your texts, your background, but I wish there was a way for us to set up other variables or some other things to specify more colours. So for example, my navigation, I have a lot more colours than two. I wish there was a way for me to set those up instead of using CSS and then the variable name and then manually injecting those.</p>\n\n\n\n<p>[00:35:34] <strong>Nathan Wrigley:</strong> Right. Overriding things. Yeah.</p>\n\n\n\n<p>[00:35:36] <strong>Johanne Courtright:</strong> Allow me to have custom keys or something where I can just say, oh, put your colours here, and then it will just generate whatever it needs to do. So if there was a way for me to have a block and specify, say, this is going to be the selector, this is the selector and this is the key. And then in the theme.json, all the person has to do is set up the key and the colour and it just applies it. That would be a nice feature.</p>\n\n\n\n<p>[00:36:04] <strong>Nathan Wrigley:</strong> Yeah, it&#8217;s curious, you know, if for example, I was to go to, I don&#8217;t know, Squarespace or something like that and build my website with their technology, I guess there&#8217;s an expectation that what you get is what you get. This is it. You know, you pay your $20 a month or whatever it may be, I have no idea, and the features that you have are what you have. Maybe you can put in a support request somewhere and ask for another feature, but basically it&#8217;s very unlikely, I imagine, to happen.</p>\n\n\n\n<p>Whereas just about everybody on the developer side of things, fiddling with WordPress, is constantly coming up with new ideas and different ways it can be adapted. And so there&#8217;s always this sense of, oh, I could build this thing into it, or I could do, and so it kind of breeds, not dissatisfaction, that&#8217;s the wrong word, but a curiosity for what it could do.</p>\n\n\n\n<p>So you&#8217;ve just given a perfect example there. You&#8217;ve got this use case, which I don&#8217;t think I would probably make much use of. I think I&#8217;m probably happy with the two colours, but clearly in your scenarios that&#8217;s a way that you would like to adapt it.</p>\n\n\n\n<p>And that&#8217;s why the platform is so cool. Maybe at some point somebody will listen to that request and will implement that for you in Core. If not, you maybe have to suffer the CSS load that you&#8217;ve got in the meantime. But that is really what separates it. You know, we&#8217;ve got this idea that, if you contribute, and you put your ideas in and you show up and you, you know, you offer your time, then that kind of stuff can be changed.</p>\n\n\n\n<p>[00:37:28] <strong>Johanne Courtright:</strong> I have to say, I know that it creates a lot of friction at the moment and how they&#8217;re guarding and guiding very specifically. And they&#8217;re clear in their vision and they want to follow that vision, and it creates some frustration for some people who want things done differently. But I appreciate that they&#8217;re doing that because it was a long term project. The frustration probably comes from, I wish it was there, what it is today, many years ago, when it came out. But I do appreciate that there&#8217;s somebody with a vision who stick to their vision because I think it&#8217;s the right way.</p>\n\n\n\n<p>[00:38:10] <strong>Nathan Wrigley:</strong> Yeah, and interestingly, everybody else&#8217;s vision can also be lived. So, you know, there&#8217;s a variety of different page builders, and I know that&#8217;s not your thing, but it is the thing of many millions of people. They love that, and that&#8217;s their preferred way of doing it. You can&#8217;t do that on these other proprietary platforms. There isn&#8217;t a different entire UX and UI that you can inject into it, but we have that, you know? And if you want to use a page builder, or you want to use whatever it is that you want to use, that&#8217;s the way it is.</p>\n\n\n\n<p>I suppose the only thing we&#8217;ve got to be mindful of is the flame was that sometimes occur. You know, people saying, well, my tool is the best tool. Anybody else that&#8217;s using anything else is missing out or what have you, or maybe stronger language than that. And just recognise that, well, the reason that you can do that is because there&#8217;s this foundational stuff, the WordPress Core.</p>\n\n\n\n<p>[00:39:00] <strong>Johanne Courtright:</strong> They&#8217;re allowing it.</p>\n\n\n\n<p>[00:39:01] <strong>Nathan Wrigley:</strong> Yeah, and it&#8217;s allowing you to have that, and you don&#8217;t have to use Gutenberg. But it does feel, it really does feel as if in the latter part of 2025, it does feel as if there&#8217;s a little bit more excitement around the Block Editor and the different bits and pieces. I don&#8217;t know if you&#8217;ve picked up on that, but there seems to be more stories. There seems to be more people shipping products that latch onto the block editor. Yours obviously is an example of that.</p>\n\n\n\n<p>[00:39:24] <strong>Johanne Courtright:</strong> The biggest hurdle is to learn it&#8217;s a different mindset, different language, it&#8217;s different in so many ways. There&#8217;s just too much to learn to jump from old way to new way. And it&#8217;s very overwhelming for a lot of people. It&#8217;s very, very overwhelming.</p>\n\n\n\n<p>[00:39:45] <strong>Nathan Wrigley:</strong> Genuinely don&#8217;t know how we bridge that gap, to be honest, because I think you&#8217;re right. If you&#8217;ve been familiar with using WordPress in its classic form, then it is, it&#8217;s seismic. But more or less, every developer that I know has at least some curiosity in Gutenberg and things like that, so probably.</p>\n\n\n\n<p>[00:40:00] <strong>Johanne Courtright:</strong> Once people fully decide to embrace it and take the time to reverse engineer and understand it, they&#8217;re like, oh, wow. All the cool stuff I can do. Yes. You know? And they change their mind completely. It&#8217;s a bit challenging because I mean, even like, let&#8217;s just say Tailwind, which is the CSS framework. I mean, it&#8217;s great. Tailwind is amazing, but when you start trying to use it with WordPress, that&#8217;s another one that fights WordPress. I stopped using it. I&#8217;m just going with SCSS and I build my own stuff. Now I have very little CSS into my blocks and it&#8217;s just, there&#8217;s no real point to have CSS framework in WordPress. You don&#8217;t need that.</p>\n\n\n\n<p>[00:40:44] <strong>Nathan Wrigley:</strong> I&#8217;m going to pivot the subject a little bit, and it&#8217;s because of a tweet that I saw yesterday, I believe it was. A friend of mine tweeted that he&#8217;s yet to see a block solution. So I don&#8217;t think that those were the words that he used, but he&#8217;s yet to see an out and out successful business built on top of blocks. So the example might be that, for example, on WordPress Core, you&#8217;ve got all of these really successful products. So you&#8217;ve got things like Gravity Forms and things like that, that have made real, they&#8217;ve got a real stable business going on. And he was questioning, have we seen that with blocks yet?</p>\n\n\n\n<p>So you are trying to make that happen. You are trying to sell a commercial product. I know that there&#8217;s, free versions and things like that, but you&#8217;re trying to sell a commercial product. How is that? What is the landscape for that at the moment? Because I&#8217;m guessing it&#8217;s not like you are printing money at the moment. I don&#8217;t know how difficult that is and whether or not it&#8217;s been the fountain of cash that maybe you&#8217;d hoped it would be.</p>\n\n\n\n<p>[00:41:44] <strong>Johanne Courtright:</strong> I don&#8217;t expect it to be a fountain of cash. I love what I do. I do it for myself first, and if other people happen to enjoy it, then But if they don&#8217;t, that&#8217;s fine, I&#8217;m using it.</p>\n\n\n\n<p>[00:41:59] <strong>Nathan Wrigley:</strong> That&#8217;s very sanguine approach. I think his thought when he made that tweet is that maybe we&#8217;re on the cusp of something. Because it feels like there&#8217;s a certain speed that the flywheel needs to achieve before people become really interested in it. I&#8217;m not sure that that has yet happened. But give it some more time, give it some more interesting products, some more attention, some more marketing and what have you. And definitely a lot of the stuff shipping in 6.9, which is actually coming out today. And then 7 next year, and all of the AI bits and pieces that are going to be put in as well. You never know. Maybe with a fair wind, we&#8217;ll be printing money for you.</p>\n\n\n\n<p>[00:42:38] <strong>Johanne Courtright:</strong> I do have a message for Matt if he listens. He needs to work on his plugin and themes website. It&#8217;s not usable at the moment. It doesn&#8217;t leave room for new development, new plugins to be seen. It needs to be feeling more like a community.</p>\n\n\n\n<p>I come from a background where I did a lot of desktop customisation. We had featured skins and themes and wallpapers and there was, people were excited. There was somebody reviewing. Think about it about how Apple does their Apple store, where they had like featured apps. Somebody went and tested a few of those plugins and featured them. They pick them. We need more, something like that.</p>\n\n\n\n<p>We also need to have a better search. Search is awful. It&#8217;s all stuffed keywords. And if you&#8217;ve been around for a while, if you&#8217;re new, there&#8217;s no way for you to rank for anything. There needs to be true categories and easier ways to find what you&#8217;re looking for.</p>\n\n\n\n<p>[00:43:37] <strong>Nathan Wrigley:</strong> Do you know, that&#8217;s a whole interesting other conversation, isn&#8217;t it? Maybe we&#8217;ll have that one time. But I get what you mean. When the iPhone came out, don&#8217;t know if you sort of remember or go back that far, but when the iPhone came out, it was this curious but beautiful object that had a lovely screen and could play songs and things. But the moment the app store came along for the iPhone, that&#8217;s I think when it became really interesting.</p>\n\n\n\n<p>And it does feel with the advent of blocks, like there&#8217;s an opportunity similar to that in that WordPress is no longer just these plugins and themes. We&#8217;ve got this whole other thing now, these blocks, these mini applications if you like, which really in many ways have full capabilities like plugins would do. And being able to surface those and find a block or a.</p>\n\n\n\n<p>[00:44:26] <strong>Johanne Courtright:</strong> You should be able to set, are you supporting Gutenberg? Is it using jQuery? Is it using those basic little things like check, check, check? And if some people are looking for those things, they should be able to find you.</p>\n\n\n\n<p>Right now it&#8217;s useless. It&#8217;s very useless, even for me looking for a plugin. Most of the plugins I found these days are because I use Google or AI, or there&#8217;s other means, but it&#8217;s very hard to find. I don&#8217;t even rank in the first 40 some pages for my navigation, so it&#8217;s ridiculous. Look for navigation, you won&#8217;t find me.</p>\n\n\n\n<p>[00:45:04] <strong>Nathan Wrigley:</strong> Okay, so maybe that&#8217;s work to be done in 2026. But hopefully somebody has heard your plea there and you never know. If they have and they want to reach out to you, well, obviously we know that you&#8217;ve got the Groundworx with an X, .dev website. Is there another place where you hang out online that people could find you if they wanted to have a chat?</p>\n\n\n\n<p>[00:45:23] <strong>Johanne Courtright:</strong> I&#8217;ve been hanging out a lot on X these days. I get a lot more response there. It seems to be WordPress community hangs out there a lot, so I think that&#8217;s going to be my platform of choice for a while.</p>\n\n\n\n<p>[00:45:36] <strong>Nathan Wrigley:</strong> Okay. In which case, into the show notes, along with the links to all of the bits and pieces that we mentioned, I will bury the link to Johanne&#8217;s X profile as well, so you can go and connect there.</p>\n\n\n\n<p>Thank you so much for chatting to me today. It&#8217;s really interesting getting your insight into all of the bits and pieces that you&#8217;ve done extending Gutenberg, but also all of the bits and pieces that you&#8217;ve done with new stuff as well. Go check it out. It&#8217;s Groundworx.dev. Johanne, thank you so much for chatting to me today.</p>\n\n\n\n<p>[00:46:01] <strong>Johanne Courtright:</strong> Thank you for inviting me. Thank you so much. It was great.</p>\n</div></details>\n\n\n\n<p>On the podcast today we have <a href=\"https://x.com/groundworxdev\">Johanne Courtright</a>.</p>\n\n\n\n<p>Johanne started working with WordPress back in 2011, moving over from a background in marketing agencies, Dreamweaver, and static HTML sites. Over the years, she’s become a skilled developer, focusing on extending WordPress through custom queries, forms, integrations with APIs, and increasingly, harnessing the power of the block editor and React.</p>\n\n\n\n<p>Johanne talks about her journey from the classic world of agency WordPress development to embracing Gutenberg, and the challenges and wins along the way. She shares her experience in building custom blocks and enhancing existing ones to better serve agencies, things like improved breakpoints, color palettes, responsive designs, and navigation, all of which aren’t offered in Core yet. These features come together in her growing open-source project, Groundworx.</p>\n\n\n\n<p>We talk about the shifting landscape from classic themes to block-based themes, and why, even in 2025, a lot of agencies and users are still hesitant to make the leap fully. Johanne explains where the block editor falls short for her use, and how Groundworx aims to plug these perceived gaps with a foundation of flexible, performant, agency-focused blocks and templates.</p>\n\n\n\n<p>You’ll hear about her approach to building modular themes with theme.json, the realities of client work and scope creep, and how the 80/20 rule shapes what belongs in Core and what’s best handled by plugins.</p>\n\n\n\n<p>We also get into the challenge of discovery in the WordPress plugin ecosystem, her wishlist for Block Editor improvements, and her take on the future of block-based businesses in WordPress.</p>\n\n\n\n<p>Whether you’re a developer eager to modernise your workflow, or just curious about extending Gutenberg for real-world use, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p><a href=\"https://groundworx.dev/products/groundworx-core/\">Groundworx Core</a></p>\n\n\n\n<p><a href=\"https://groundworx.dev/products/groundworx-navigation/\">Groundworx Navigation</a></p>\n\n\n\n<p><a href=\"https://gutenbergtimes.com\">Gutenberg Times</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Dec 2025 15:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:46;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Matt: Dries OSS\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150795\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ma.tt/2025/12/dries-oss/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:734:\"<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>A more accurate framing would be that Fizzy is <a href=\"https://en.wikipedia.org/wiki/Source-available_software\">source available</a>. You can read it, run it, and modify it. But DHH&#8217;s company is keeping the SaaS rights because they want to be able to build a sustainable business. That is defensible and generous, but it is <em>not</em> open source.</p>\n</blockquote>\n\n\n\n<p>Dries Buytaert follows up <a href=\"https://ma.tt/2025/12/dhh-open-source/\">on my response to DHH</a> with <a href=\"https://dri.es/source-available-is-not-open-source-and-that-is-okay\">&#8216;Source available&#8217; is not open source (and that&#8217;s okay)</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Dec 2025 03:13:28 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:47;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"Open Channels FM: Growth, Hackathons, and Gratitude Lessons from an Eventful 2025\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=113334\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"https://openchannels.fm/growth-hackathons-and-gratitude-lessons-from-an-eventful-2025/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:219:\"Zach Stepek and Carl Alexander recap their 2025 experiences, highlighting personal growth, industry events, business developments, and health journeys. They emphasize gratitude and reflect on goals for a promising 2026.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 09 Dec 2025 14:36:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:48;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Matt: DHH &amp;amp; Open Source\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150789\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"https://ma.tt/2025/12/dhh-open-source/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4992:\"<p>I might have a new prayer: God, give me confidence of DHH <a href=\"https://x.com/dhh/status/1996627792008827342\">claiming his proprietary license is Open Source</a>.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-150790\" height=\"179\" src=\"https://i0.wp.com/ma.tt/files/2025/12/dhh-tweet-1024x303.png?resize=604%2C179&#038;quality=80&#038;ssl=1\" width=\"604\" /></figure>\n\n\n\n<p>37signals/Basecamp has a great new product called <a href=\"https://www.fizzy.do/\">Fizzy</a>, whose brilliance and innovative qualities are being distracted from by its co-creator David Heinmeier Hansson’s insistence on calling it open source. &#8220;One more thing&#8230;  Fizzy is open source and 100% free to run yourself.&#8221;</p>\n\n\n\n<p>Thanks to Freedom of Speech, DHH is free to describe his proprietary software as Open Source, a form of <a href=\"https://ma.tt/2025/10/greenwashing/\">greenwashing</a>, and even though he wants to “Well akshually” <a href=\"https://x.com/codejake/status/1996629945150591448\">denigrate those saying why this is BS</a>, we as free citizens are free to explain why, despite how fast he talks and confident he sounds, he’s not always right.</p>\n\n\n\n<p>Myself and other “Actually Open Source” leaders (including DHH) who release software under licenses that meet <a href=\"https://opensource.org/osd\">a common definition of Open Source</a> benefit from decades of prior art and an incredible foundation that lays out the philosophy and definition of what defines open source.</p>\n\n\n\n<p>For the layperson, though, it might be helpful to break things down in an analogy of authoritarian vs democratic regimes, or a core question of who holds the power.</p>\n\n\n\n<p>Proprietary licenses may grant things that feel like freedoms; for example, Fizzy’s O’Saasy license lets you download the source code, run it yourself, modify it, and <a href=\"https://github.com/basecamp/fizzy\">use a public bug tracker, and you can see the software&#8217;s source control history</a>. That’s cool! Also, in the past several years, there have been Middle Eastern countries that have just now allowed women to drive cars. That’s great! However, as a free person choosing to use this software, or choosing to live in a country, you have to ask yourself: Am I still free?</p>\n\n\n\n<p>No, you’re not. You are allowed to do some things that are in and of themselves good, but ultimately, it’s not built on a foundation of <a href=\"https://ma.tt/2014/01/four-freedoms/\">an inalienable right </a>or constitution; it’s at the whim of the leader. <a href=\"https://www.fizzy.do/license\">O’Saasy license has this restriction</a>:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>No licensee or downstream recipient may use the Software (including any modified or derivative versions) to directly compete with the original Licensor by offering it to third parties as a hosted, managed, or Software-as-a-Service (SaaS) product or cloud service where the primary value of the service is the functionality of the Software itself.</p>\n</blockquote>\n\n\n\n<p>Oh wow, I can’t compete with the leader. In how they choose to operate their business today, or however they might choose to in the future. My freedoms are at their whim. This violates rule 5 of the OSI definition of Open Source: “The license must not discriminate against any person or group of persons.”</p>\n\n\n\n<p>I’d like to choose software and live in a society that doesn’t discriminate.</p>\n\n\n\n<p>It’s not uncommon for people trying to take away your freedom to want to use the same words as those in truly free societies. North Korea calls itself the Democratic People&#8217;s Republic of Korea. Why? <a href=\"https://www.google.com/search?q=why+does+north+korea+call+itself+democratic\">Per Google&#8217;s AI</a>:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p><strong>Socialist Definition of Democracy</strong> During the Cold War, the Soviet Union and its allies used &#8220;democracy&#8221; to mean &#8220;people&#8217;s power&#8221; through a single ruling party, representing the working class, as opposed to the multi-party &#8220;bourgeois&#8221; democracy of the West. North Korea adopted this lexicon, as did other communist states like the German Democratic Republic (East Germany).</p>\n</blockquote>\n\n\n\n<p>Yeah, really democratic. In that sense, you can say O&#8217;Saasy is an “open” “source” license. Perhaps a bubble of people will agree with you. But the rest of the world will use common sense and see that as a <strong>fraud</strong>. And most disappointingly for <a href=\"https://37signals.com/\">37signals</a>, a company that prides itself on high integrity, it&#8217;s <strong>false advertising</strong>.</p>\n\n\n\n<p>(For what it&#8217;s worth, <a href=\"https://x.com/photomatt/status/1996353545717924209\">I tried to resolve this quietly with Jason Fried a few days ago</a>.)</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 09 Dec 2025 05:30:06 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:49;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:27:\"Matt: Happy Birthday Kinsey\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150776\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ma.tt/2025/12/kinsey-70/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3384:\"<p>Yesterday I had the great honor and privilege of attending a colleague’s 70<sup>th</sup> birthday party. You may not have heard his name before, but <a href=\"https://kinsey.nyc/\">Kinsey Wilson</a> has been at the center of shaping journalism with a movie-worthy career that started at the bottom as a crime reporter in Chicago, and has taken him to the highest echelons at NPR, the New York Times, and, most recently, we’ve been lucky to have him at Automattic.</p>\n\n\n\n<p>Kinsey brings a journalistic curiosity and passion for finding truth, paired with a deep optimism and creativity for seeing around the corner for how technology can transform how we consume and produce media.</p>\n\n\n\n<p>While <a href=\"https://en.wikipedia.org/wiki/Kinsey_Wilson\">his Wikipedia page</a> or <a href=\"https://kinsey.nyc/about/\">biography</a> provides appetizers to some of what he&#8217;s done, Kinsey has led such a rich and beautiful life that any attempt to summarize it ends up being criminally reductive. The best you can hope for is to give a taste of his person through vignettes.</p>\n\n\n\n<p>A beautiful snippet from the montage of accolades at his birthday was how Kinsey was someone you’d follow into battle. I’ve learned so much from seeing the empathy, candor, and integrity he brings to every team he leads, which engenders an incredible loyalty I&#8217;ve rarely seen in my career. When he left NPR, 62 colleagues made <a href=\"https://web.archive.org/web/20141107124059/http://www.infinitekinsey.com/playlist/\">an “Infinite Kinsey” website of accolades</a>. </p>\n\n\n\n<p>That sort of thing is rare, and it’s been an honor and a privilege to work alongside him to democratize publishing.</p>\n\n\n\n<p>One of those colleagues, <a href=\"https://elisehu.com/\">Elise Hu</a>, introduced us while he was at the New York Times and while my intention when I first met him was to get more WordPress at the Times, my imagination was sparked by thinking of how he could bring his experience to help shape WordPress and Automattic, hence my pivot into recruiting him.</p>\n\n\n\n<p>Kinsey&#8217;s impact on journalism (and podcasting!) at NPR and New York Times is easy to understand, but less well-known is how he came into Automattic and got deep into understanding WordPress and seeing it as a platform that could enable the newsrooms and journalists to accomplish their mission in a more efficient way with the project he leads, <a href=\"https://newspack.com/\">Newspack</a>. </p>\n\n\n\n<p>He’s a fierce steward of the <a href=\"https://en.wikipedia.org/wiki/Fourth_Estate\">Fourth Estate</a>. </p>\n\n\n\n<p>Newspack and its team’s close relationship to customers invents solutions on top of WordPress that delight its users and percolate and influence everything we do at <a href=\"https://automattic.com/\">Automattic</a>. They&#8217;re one of the teams that sets the bar for others in the company.</p>\n\n\n\n<p>To Kinsey, I’ll leave you with a quote from one of my other inspirations, Charlie Munger, who at the <a href=\"https://www.wsj.com/finance/investing/charlie-munger-life-final-years-berkshire-7c20c18e\">tender age of 99 shared a wish with a visitor</a>, <em>“Oh, to be 86 again.”</em></p>\n\n\n\n<p>I’ll try not to be too tech-bro optimist and say that 70 is the new 40, but I look forward to seeing the ripples that you have on the future of publishing for many years to come. </p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 07 Dec 2025 21:37:45 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:9:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Sun, 18 Jan 2026 04:55:30 GMT\";s:12:\"content-type\";s:8:\"text/xml\";s:13:\"last-modified\";s:29:\"Sun, 18 Jan 2026 04:30:19 GMT\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}s:5:\"build\";i:1768710361;s:21:\"cache_expiration_time\";i:1768755331;s:23:\"__cache_expiration_time\";i:1768755331;}','off'),(264,'_site_transient_timeout_feed_mod_d117b5738fbd35bd8c0391cda1f2b5d9','1768755331','off'),(265,'_site_transient_feed_mod_d117b5738fbd35bd8c0391cda1f2b5d9','1768712131','off'),(266,'_transient_timeout_dash_v2_88ae138922fe95674369b1cb3d215a2b','1768755331','off'),(267,'_transient_dash_v2_88ae138922fe95674369b1cb3d215a2b','<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wordpress.org/news/2026/01/wordpress-playground-speed-stability-momentum/\'>WordPress Playground Br