\"px\",\"size\":32,\"sizes\":[]},\"typography_font_size_tablet\":{\"unit\":\"px\",\"size\":40,\"sizes\":[]},\"typography_font_size_mobile\":{\"unit\":\"px\",\"size\":24,\"sizes\":[]},\"typography_font_weight\":\"700\"}}],\"isInner\":false},{\"id\":\"faq_3b39e84f\",\"elType\":\"section\",\"settings\":{\"background_background\":\"classic\",\"background_color\":\"#f2ede7\",\"background_image\":{\"url\":\"http:///wp-content/themes/frederica-passos/images/srosa.svg\",\"id\":\"\",\"size\":\"custom\"},\"background_position\":\"center center\",\"background_repeat\":\"no-repeat\",\"background_size\":\"70%\",\"padding\":{\"unit\":\"px\",\"top\":\"96\",\"right\":\"0\",\"bottom\":\"96\",\"left\":\"0\",\"isLinked\":false}},\"elements\":[{\"id\":\"faq_title_9e271dd0\",\"elType\":\"widget\",\"widgetType\":\"heading\",\"settings\":{\"title\":\"Perguntas Frequentes\",\"header_size\":\"h2\",\"align\":\"center\",\"title_color\":\"#1f2937\",\"typography_typography\":\"custom\",\"typography_font_family\":\"JH Caudemars\",\"typography_font_size\":{\"unit\":\"px\",\"size\":48,\"sizes\":[]},\"typography_font_size_tablet\":{\"unit\":\"px\",\"size\":56,\"sizes\":[]},\"typography_font_size_mobile\":{\"unit\":\"px\",\"size\":36,\"sizes\":[]},\"typography_font_weight\":\"500\",\"margin\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"64\",\"left\":\"0\",\"isLinked\":false}}},{\"id\":\"faq_accordion_8223b56a\",\"elType\":\"widget\",\"widgetType\":\"accordion\",\"settings\":{\"tabs\":[{\"tab_title\":\"Du00e1 formau00e7u00f5es ou palestras sobre sau00fade mental?\",\"tab_content\":\"Sim. Participo regularmente em au00e7u00f5es de formau00e7u00e3o, palestras e eventos sobre sau00fade mental, com foco especial na sau00fade da mulher, sau00fade perinatal e diversidade de gu00e9nero.\",\"icon\":{\"value\":\"http:///wp-content/themes/frederica-passos/images/icons/PALESTRAS.svg\",\"library\":\"image\"}},{\"tab_title\":\"Tem algum programa de apoio especu00edfico para pais de pessoas transexuais?\",\"tab_content\":\"Sim. Disponibilizo acompanhamento individual para pais(ou pessoa de referu00eancia) de pessoas transexuais, ajudando a lidar com o processo de aceitau00e7u00e3o e adaptau00e7u00e3o com empatia e informau00e7u00e3o especializada.\",\"icon\":{\"value\":\"http:///wp-content/themes/frederica-passos/images/icons/PAIS_TRANS.svg\",\"library\":\"image\"}},{\"tab_title\":\"Pode falar com outros profissionais de sau00fade, como o meu mu00e9dico de famu00edlia?\",\"tab_content\":\"Sim, mas sempre com o seu consentimento. Tenho uma abordagem muito multidisciplinar e de trabalho em equipa, a articulau00e7u00e3o com outros profissionais u00e9 fundamental para garantir um cuidado integrado e eficaz.\",\"icon\":{\"value\":\"http:///wp-content/themes/frederica-passos/images/icons/FALARPROF.svg\",\"library\":\"image\"}},{\"tab_title\":\"Quais su00e3o as suas u00e1reas de especialidade como psiquiatra?\",\"tab_content\":\"Sou especializada em sau00fade mental da mulher, sau00fade perinatal (gru00e1vidas e pu00f3s-parto), identidade de gu00e9nero e sexualidade. Tambu00e9m trabalho com perturbau00e7u00e3o de hiperatividade e du00e9fice de atenu00e7u00e3o (PHDA) no adulto e Psiquiatria no geral.\",\"icon\":{\"value\":\"http:///wp-content/themes/frederica-passos/images/icons/ESPECIALIDADES.svg\",\"library\":\"image\"}},{\"tab_title\":\"Trabalha com acompanhamento psiquiu00e1trico durante a gravidez e pu00f3s-parto?\",\"tab_content\":\"Sim. Fau00e7o acompanhamento antes, durante e apu00f3s a gravidez, com foco na sau00fade emocional da mulher, do casal e na adaptau00e7u00e3o u00e0 parentalidade.\",\"icon\":{\"value\":\"http:///wp-content/themes/frederica-passos/images/icons/GRAVIDEZ.svg\",\"library\":\"image\"}},{\"tab_title\":\"Faz seguimento de pessoas transexuais em processo de transiu00e7u00e3o?\",\"tab_content\":\"Sim. Acompanho pessoas em todas as fases da transiu00e7u00e3o de gu00e9nero, oferecendo apoio emocional e, quando necessu00e1rio, orientau00e7u00e3o para as outras especialidades mu00e9dicas para realizarem terapia hormonal ou as intervenu00e7u00f5es ciru00fargicas pertinentes.\",\"icon\":{\"value\":\"http:///wp-content/themes/frederica-passos/images/icons/TRANS.svg\",\"library\":\"image\"}},{\"tab_title\":\"Trabalha com adolescentes ou apenas adultos?\",\"tab_content\":\"Atendo apenas adultos, portanto individuos a partir dos 18 anos\",\"icon\":{\"value\":\"http:///wp-content/themes/frederica-passos/images/icons/ADOLESCENTES.svg\",\"library\":\"image\"}},{\"tab_title\":\"Faz teleconsultas?\",\"tab_content\":\"Sim. Acredito na acessibilidade aos serviu00e7os de sau00fade mental, e por vezes as teleconsultas su00e3o uma soluu00e7u00e3o interessante para conseguir conjugar o tratamento com a vida pessoal e profissional.\",\"icon\":{\"value\":\"http:///wp-content/themes/frederica-passos/images/icons/TELECONSULTAS.svg\",\"library\":\"image\"}},{\"tab_title\":\"Qual a durau00e7u00e3o das consultas?\",\"tab_content\":\"Cada consulta dura em mu00e9dia 45-60minutos.\",\"icon\":{\"value\":\"http:///wp-content/themes/frederica-passos/images/icons/DURACAO.svg\",\"library\":\"image\"}}],\"title_html_tag\":\"h3\",\"title_color\":\"#70309e\",\"icon_color\":\"#70309e\",\"icon_active_color\":\"#f56428\",\"icon_align\":\"left\",\"toggle_icon_active_color\":\"#f56428\",\"content_color\":\"#6b7280\",\"typography_title_typography\":\"custom\",\"typography_title_font_family\":\"Neue Montreal\",\"typography_title_font_weight\":\"500\",\"typography_title_font_size\":{\"unit\":\"px\",\"size\":18,\"sizes\":[]},\"typography_content_typography\":\"custom\",\"typography_content_font_family\":\"Neue Montreal\",\"typography_content_font_size\":{\"unit\":\"px\",\"size\":16,\"sizes\":[]}}}],\"isInner\":false},{\"id\":\"contato_dae8ec68\",\"elType\":\"section\",\"settings\":{\"background_background\":\"classic\",\"background_color\":\"#f56428\",\"background_image\":{\"url\":\"http:///wp-content/themes/frederica-passos/images/fundo2.svg\",\"id