ayout\":\"boxed\",\"background_background\":\"classic\",\"background_color\":\"#f2ede7\",\"padding\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":true}},\"elements\":[{\"id\":\"about_col_0c06fb2e\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"about_html_e899f198\",\"elType\":\"widget\",\"widgetType\":\"html\",\"settings\":{\"html\":\"<style>@font-face{font-family:\'JH Caudemars\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/jhcaudemars-medium.otf\') format(\'opentype\');font-weight:500;font-style:normal;font-display:swap}@font-face{font-family:\'NeueMontreal\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/NeueMontreal-Regular.otf\') format(\'opentype\');font-weight:400;font-style:normal;font-display:swap}@font-face{font-family:\'NeueMontreal\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/NeueMontreal-Medium.otf\') format(\'opentype\');font-weight:500;font-style:normal;font-display:swap}@font-face{font-family:\'NeueMontreal\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/NeueMontreal-Bold.otf\') format(\'opentype\');font-weight:700;font-style:normal;font-display:swap}.about-section{max-width:1280px;margin:0 auto;padding:96px 16px;background:#f2ede7}.about-content{display:flex;flex-direction:column;gap:32px}@media(min-width:1024px){.about-content{flex-direction:row;align-items:center;gap:48px}}.about-text{flex:1.5}.about-text h2{font-family:\'JH Caudemars\',serif!important;font-size:48px;color:#70309e;margin-bottom:24px;line-height:1.2}@media(min-width:768px){.about-text h2{font-size:64px}}@media(min-width:1024px){.about-text h2{font-size:80px}}.about-text p{font-family:\'NeueMontreal\',sans-serif!important;font-size:16px;color:#374151;line-height:1.75;margin-bottom:16px}@media(min-width:768px){.about-text p{font-size:18px}}.about-text strong{font-weight:600}.about-image{flex:1.5;width:100%}.about-image img{width:100%;aspect-ratio:3/4;object-fit:cover;border-radius:8px}@media(min-width:1024px){.about-image img{aspect-ratio:4/5}}</style><div class=\'about-section\' id=\'sobre\'><div class=\'about-content\'><div class=\'about-text\'><h2>Uma Carreira Dedicada à Saúde Mental da Mulher</h2><p><strong>Dra Frederica Passos Barbizani</strong> é psiquiatra especializada em Saúde Mental da Mulher. Com foco no universo feminino, acredita que toda mulher merece cuidados de saúde mental que respeitem suas particularidades biológicas, psicológicas e sociais.</p><p>Especializou-se em Psiquiatria no Hospital Beatriz Ângelo, com foco em Psiquiatria da Mulher e Psiquiatria Perinatal. Sua prática clínica baseia-se em pilares fundamentais: cuidado humanizado, evidência científica, abordagem integral e empoderamento da paciente. Dedica-se também à investigação científica, com interesse particular em perturbações do humor no período perinatal, impacto hormonal na saúde mental, sexualidade, identidade de género, competências parentais e dinâmicas familiares.</p></div><div class=\'about-image\'><img src=\'/wp-content/themes/frederica-passos/images/fotofrederica.webp\' alt=\'Dra Frederica Passos\'/></div></div></div>\"}}]}]},{\"id\":\"orange_a72b3655\",\"elType\":\"section\",\"settings\":{\"layout\":\"full_width\",\"background_background\":\"classic\",\"background_color\":\"#f56428\",\"padding\":{\"unit\":\"px\",\"top\":\"16\",\"right\":\"0\",\"bottom\":\"16\",\"left\":\"0\",\"isLinked\":true}},\"elements\":[{\"id\":\"orange_col_78b2d581\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"orange_html_07919442\",\"elType\":\"widget\",\"widgetType\":\"html\",\"settings\":{\"html\":\"<style>.orange-band{position:relative;background:#f56428;padding:16px 0;overflow:hidden;width:100vw;margin:0;position:relative;left:50%;right:50%;margin-left:-50vw;margin-right:-50vw}@media(min-width:768px){.orange-band{padding:24px 0}}.orange-band-pattern{position:absolute;background-image:url(/wp-content/the