al;card.classList.remove(\'active\',\'left\',\'right\',\'hidden\');if(position===0){card.classList.add(\'active\')}else if(position===total-1){card.classList.add(\'left\')}else if(position===1){card.classList.add(\'right\')}else{card.classList.add(\'hidden\')}});dots.forEach((dot,index)=>{dot.classList.toggle(\'active\',index===currentFormacao)})}function next(){currentFormacao=(currentFormacao+1)%total;updateCarousel()}function prev(){currentFormacao=(currentFormacao-1+total)%total;updateCarousel()}function goTo(index){currentFormacao=index;updateCarousel()}if(prevBtn){prevBtn.addEventListener(\'click\',prev)}if(nextBtn){nextBtn.addEventListener(\'click\',next)}dots.forEach((dot,index)=>{dot.addEventListener(\'click\',()=>goTo(index))});updateCarousel()})()</script>\"}}]}]},{\"id\":\"stats_8229b853\",\"elType\":\"section\",\"settings\":{\"layout\":\"boxed\",\"background_background\":\"classic\",\"background_color\":\"#70309e\",\"padding\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":true}},\"elements\":[{\"id\":\"stats_col_8e1dc9d1\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"stats_html_d80f6086\",\"elType\":\"widget\",\"widgetType\":\"html\",\"settings\":{\"html\":\"<style>@font-face{font-family:\'JH Caudemars\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/jhcaudemars-medium.otf\') format(\'opentype\');font-weight:500;font-style:normal;font-display:swap}@font-face{font-family:\'NeueMontreal\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/NeueMontreal-Regular.otf\') format(\'opentype\');font-weight:400;font-style:normal;font-display:swap}@font-face{font-family:\'NeueMontreal\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/NeueMontreal-Medium.otf\') format(\'opentype\');font-weight:500;font-style:normal;font-display:swap}@font-face{font-family:\'NeueMontreal\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/NeueMontreal-Bold.otf\')