:96px 16px;background:#f2ede7;overflow:hidden;left:50%;right:50%;margin-left:-50vw;margin-right:-50vw}.faq-section::before{content:\'\';position:absolute;inset:0;top:0;left:0;right:0;bottom:0;background-image:url(/wp-content/themes/frederica-passos/images/srosa.svg);background-size:200% auto;background-position:center;background-repeat:no-repeat;opacity:1;z-index:0;width:100%;height:100%}.faq-content-wrapper{position:relative;z-index:10;max-width:896px;margin:0 auto}.faq-title{font-family:\'JH Caudemars\',serif!important;font-size:48px;color:#111827;text-align:center;margin-bottom:64px;line-height:1.2}@media(min-width:768px){.faq-title{font-size:64px;margin-bottom:80px}}@media(min-width:1024px){.faq-title{font-size:80px}}.faq-list{display:flex;flex-direction:column;gap:16px}.faq-item{background:#fff;border-radius:8px;border:1px solid #e5e7eb;overflow:hidden}.faq-button{width:100%;padding:20px;display:flex;align-items:center;gap:16px;text-align:left;background:none;border:none;cursor:pointer;transition:background 0.2s}.faq-button:hover{background:#f9fafb}.faq-icon{flex-shrink:0;width:56px;height:56px;border-radius:8px;background:#70309e;display:flex;align-items:center;justify-content:center;transition:all 0.3s}.faq-icon img{width:24px;height:24px;object-fit:contain}@media(min-width:640px){.faq-icon{width:56px;height:56px}.faq-icon img{width:28px;height:28px}}.faq-item.open .faq-icon{background:#f56428;transform:scale(1.1)}.faq-item.open .faq-icon img{transform:scale(1.15)}.faq-question{flex:1;font-family:\'NeueMontreal\',sans-serif!important;font-size:16px;font-weight:500;color:#111827;padding-right:16px}@media(min-width:768px){.faq-question{font-size:18px}}.faq-arrow{flex-shrink:0;width:24px;height:24px;color:#f56428;transition:transform 0.4s}.faq-item.open .faq-arrow{transform:rotate(180deg)}.faq-content{max-height:0;overflow:hidden;transition:max-height 0.4s,opacity 0.3s;opacity:0}.faq-item.open .faq-content{max-height:500px;opacity:1}.faq-answer{padding:0 20px 20px 20px;border-top:1px solid #f3f4f6;margin-top:0;font-family:\'NeueMontreal\',sans-serif!important;font-size:16px;color:#374151;line-height:1.75}@media(min-width:768px){.faq-answer{font-size:18px}}</style><div class=\'faq-section\'><div class=\'faq-content-wrapper\'><h2 class=\'faq-title\'>Perguntas Frequentes</h2><div class=\'faq-list\'><div class=\'faq-item\'><button class=\'faq-button\' onclick=\'this.parentElement.classList.toggle(\\\"open\\\")\'><div class=\'faq-icon\'><img src=\'/wp-content/themes/frederica-passos/images/icons/PALESTRAS.svg\' alt=\'\'/></div><span class=\'faq-question\'>Dá formações ou palestras sobre saúde mental?</span><svg class=\'faq-arrow\' fill=\'none\' stroke=\'currentColor\' viewBox=\'0 0 24 24\'><path stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/></svg></button><div class=\'faq-content\'><p class=\'faq-answer\'>Sim. Participo regularmente em ações de formação, palestras e eventos sobre saúde mental, com foco especial na saúde da mulher, saúde perinatal e diversidade de género.</p></div></div><div class=\'faq-item\'><button class=\'faq-button\' onclick=\'this.parentElement.classList.toggle(\\\"open\\\")\'><div class=\'faq-icon\'><img src=\'/wp-content/themes/frederica-passos/images/icons/PAIS_TRANS.svg\' alt=\'\'/></div><span class=\'faq-question\'>Tem algum programa de apoio específico para pais de pessoas transexuais?</span><svg class=\'faq-arrow\' fill=\'none\' stroke=\'currentColor\' viewBox=\'0 0 24 24\'><path stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/></svg></button><div class=\'faq-content\'><p class=\'faq-answer\'>Sim. Disponibilizo acompanhamento individual para pais(ou pessoa de referência) de pessoas transexuais, ajudando a lidar com o processo de aceitação e adaptação com empatia e informação especializada.</p></div></div><div class=\'faq-item\'><button class=\'faq-button\' onclick=\'this.parentElement.classList.toggle(\\\"open\\\")\'><div class=\'faq-icon\'><img src=\'/wp-content/themes/frederica-passos/images/icons/FALARPROF.svg\' alt=\'\'/></div><span class=\'faq-question\'>Pode falar com outros profissionais de saúde, como o meu médico de família?</span><svg class=\'faq-arrow\' fill=\'none\' stroke=\'currentColor\' viewBox=\'0 0 24 24\'><path stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/></svg></button><div class=\'faq-content\'><p class=\'faq-answer\'>Sim, mas sempre com o seu consentimento. Tenho uma abordagem muito multidisciplinar e de trabalho em equipa, a articulação com outros profissionais é fundamental para garantir um cuidado integrado e eficaz.</p></div></div><div class=\'faq-item\'><button class=\'faq-button\' onclick=\'this.parentElement.classList.toggle(\\\"open\\\")\'><div class=\'faq-icon\'><img src=\'/wp-content/themes/frederica-passos/images/icons/ESPECIALIDADES.svg\' alt=\'\'/></div><span class=\'faq-question\'>Quais são as suas áreas de especialidade como psiquiatra?</span><svg class=\'faq-arrow\' fill=\'none\' stroke=\'currentColor\' viewBox=\'0 0 24 24\'><path stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/></svg></button><div class=\'faq-content\'><p class=\'faq-answer\'>Sou especializada em saúde mental da mulher, saúde perinatal (grávidas e pós-parto), identidade de género e sexualidade. Também trabalho com perturbação de hiperatividade e défice de atenção (PHDA) no adulto e Psiquiatria no geral.</p></div></div><div class=\'faq-item\'><button class=\'faq-button\' onclick=\'this.parentElement.classList.toggle(\\\"open\\\")\'><div class=\'faq-icon\'><img src=\'/wp-content/themes/frederica-passos/images/icons/GRAVIDEZ.svg\' alt=\'\'/></div><span class=\'faq-question\'>Trabalha com acompanhamento psiquiátrico durante a gravidez e pós-parto?</span><svg class=\'faq-arrow\' fill=\'none\' stroke=\'currentColor\' viewBox=\'0 0 24 24\'><path stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/></svg></button><div class=\'faq-content\'><p class=\'faq-answer\'>Sim. Faço acompanhamento antes, durante e após a gravidez, com foco na saúde emocional da mulher, do casal e na adaptação à parentalidade.</p></div></div><div class=\'faq-item\'><button class=\'faq-button\' onclick=\'this.parentElement.classList.toggle(\\\"open\\\")\'><div class=\'faq-icon\'><img src=\'/wp-content/themes/frederica-passos/images/icons/TRANS.svg\' alt=\'\'/></div><span class=\'faq-question\'>Faz seguimento de pessoas transexuais em processo de transição?</span><svg class=\'faq-arrow\' fill=\'none\' stroke=\'currentColor\' viewBox=\'0 0 24 24\'><path stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/></svg></button><div class=\'faq-content\'><p class=\'faq-answer\'>Sim. Acompanho pessoas em todas as fases da transição de género, oferecendo apoio emocional e, quando necessário, orientação para as outras especialidades médicas para realizarem terapia hormonal ou as intervenções cirúrgicas pertinentes.</p></div></div><div class=\'faq-item\'><button class=\'faq-button\' onclick=\'this.parentElement.classList.toggle(\\\"open\\\")\'><div class=\'faq-icon\'><img src=\'/wp-content/themes/frederica-passos/images/icons/ADOLESCENTES.svg\' alt=\'\'/></div><span class=\'faq-question\'>Trabalha com adolescentes ou apenas adultos?</span><svg class=\'faq-arrow\' fill=\'none\' stroke=\'currentColor\' viewBox=\'0 0 24 24\'><path stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/></svg></button><div class=\'faq-content\'><p class=\'faq-answer\'>Atendo apenas adultos, portanto individuos a partir dos 18 anos</p></div></div><div class=\'faq-item\'><button class=\'faq-button\' onclick=\'this.parentElement.classList.toggle(\\\"open\\\")\'><div class=\'faq-icon\'><img src=\'/wp-content/themes/frederica-passos/images/icons/TELECONSULTAS.svg\' alt=\'\'/></div><span class=\'faq-question\'>Faz teleconsultas?</span><svg class=\'faq-arrow\' fill=\'none\' stroke=\'currentColor\' viewBox=\'0 0 24 24\'><path stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/></svg></button><div class=\'faq-content\'><p class=\'faq-answer\'>Sim. Acredito na acessibilidade aos serviços de saúde mental, e por vezes as teleconsultas são uma solução interessante para conseguir conjugar o tratamento com a vida pessoal e profissional.</p></div></div><div class=\'faq-item\'><button class=\'faq-button\' onclick=\'this.parentElement.classList.toggle(\\\"open\\\")\'><div class=\'faq-icon\'><img src=\'/wp-content/themes/frederica-passos/images/icons/DURACAO.svg\' alt=\'\'/></div><span class=\'faq-question\'>Qual a duração das consultas?</span><svg class=\'faq-arrow\' fill=\'none\' stroke=\'currentColor\' viewBox=\'0 0 24 24\'><path stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/></svg></button><div class=\'faq-content\'><p class=\'faq-answer\'>Cada consulta dura em média 45-60minutos.</p></div></div></div></div></div>\"}}]}]},{\"id\":\"contato_7a6fc30b\",\"elType\":\"section\",\"settings\":{\"layout\":\"full_width\",\"background_background\":\"classic\",\"background_color\":\"#f56428\",\"background_image\":{\"url\":\"\"},\"background_size\":\"cover\",\"padding\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":true}},\"elements\":[{\"id\":\"contato_col_dd6c0a47\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"contato_html_4ea1fe83\",\"elType\":\"widget\",\"widgetType\":\"html\",\"settings\":{\"html\":\"<style>@font-face{font-family:\'JH Caudemars\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/jhcaudemars-medium.otf\') format(\'opentype\');font-weight:500;font-style:normal;font-display:swap}@font-face{font-family:\'NeueMontreal\';src:url(\'/wp-content/themes/frederica-passos/images/fonts/NeueMontreal-Regula