255, 255, 0.4) !important;\n    box-shadow: 0 0 0 2px rgba(255, 255, 255, 0.1);\n}\n\n\n\n\ndocument.addEventListener(\"DOMContentLoaded\", function() {\n    console.log(\"🚀 Site Frederica Passos - Interatividade Carregada!\");\n\n    // Hero Carousel\n    let currentSlide = 0;\n    const slides = document.querySelectorAll(\".slide-roxo, .slide-cinza, .slide-laranja\");\n    const dots = document.querySelectorAll(\".slide-dot\");\n    const prevBtn = document.querySelector(\".prev-slide\");\n    const nextBtn = document.querySelector(\".next-slide\");\n\n    function showSlide(index) {\n        // Esconder todos os slides\n        slides.forEach(slide =&gt; slide.style.display = \"none\");\n        dots.forEach(dot =&gt; dot.style.backgroundColor = \"rgba(255, 255, 255, 0.5)\");\n\n        // Mostrar slide ativo\n        slides[index].style.display = \"block\";\n        dots[index].style.backgroundColor = \"rgba(255, 255, 255, 1)\";\n        currentSlide = index;\n    }\n\n    // Event listeners\n    if (prevBtn) {\n        prevBtn.addEventListener(\"click\", () =&gt; {\n            const newIndex = currentSlide === 0 ? slides.length - 1 : currentSlide - 1;\n            showSlide(newIndex);\n        });\n    }\n\n    if (nextBtn) {\n        nextBtn.addEventListener(\"click\", () =&gt; {\n            const newIndex = currentSlide === slides.length - 1 ? 0 : currentSlide + 1;\n            showSlide(newIndex);\n        });\n    }\n\n    dots.forEach((dot, index) =&gt; {\n        dot.addEventListener(\"click\", () =&gt; showSlide(index));\n    });\n\n    // Auto-play do carrossel\n    setInterval(() =&gt; {\n        const newIndex = currentSlide === slides.length - 1 ? 0 : currentSlide + 1;\n        showSlide(newIndex);\n    }, 5000);\n\n    // FAQ Accordion\n    document.querySelectorAll(\".faq-toggle\").forEach(button =&gt; {\n        button.addEventListener(\"click\", function() {\n            const content = this.nextElementSibling;\n            const isOpen = content.classList.contains(\"open\");\n\n            // Fechar todos os outros\n            document.querySelectorAll(\".faq-content\").forEach(item =&gt; {\n                item.classList.remove(\"open\");\n            });\n\n            // Abrir/fechar o clicado\n            if (!isOpen) {\n                content.classList.add(\"open\");\n            }\n        });\n    });\n\n    // Menu mobile\n    const mobileMenuBtn = document.getElementById(\"mobile-menu-btn\");\n    const mobileMenu = document.getElementById(\"mobile-menu\");\n\n    if (mobileMenuBtn &amp;&amp; mobileMenu) {\n        mobileMenuBtn.addEventListener(\"click\", function() {\n            mobileMenu.classList.toggle(\"show\");\n        });\n    }\n\n    // Scroll to section\n    document.querySelectorAll(\".nav-item, .mobile-nav-item\").forEach(item =&gt; {\n        item.addEventListener(\"click\", function(e) {\n            e.preventDefault();\n            const sectionId = this.getAttribute(\"data-section\");\n            const element = document.getElementById(sectionId);\n\n            if (element) {\n                const offset = 80;\n                const elementPosition = element.getBoundingClientRect().top;\n                const offsetPosition = elementPosition + window.pageYOffset - offset;\n\n                window.scrollTo({\n                    top: offsetPosition,\n                    behavior: \"smooth\"\n                });\n            }\n\n            // Fechar menu mobile\n            if (mobileMenu) {\n                mobileMenu.classList.remove(\"show\");\n            }\n        });\n    });\n\n    // Header scroll effect\n    let lastScrollY = window.scrollY;\n    let isHeaderVisible = true;\n\n    window.addEventListener(\"scroll\", function() {\n        const currentScrollY = window.scrollY;\n        const header = document.getElementById(\"header\");\n\n        if (currentScrollY  lastScrollY &amp;&amp; currentScrollY &gt; 100) {\n            if (isHeaderVisible) {\n                header.style.transform = \"translateY(-100%)\";\n                isHeaderVisible = false;\n            }\n        } else if (currentScrollY  300) {\n                scrollTopBtn.style.opacity = \"1\";\n                scrollTopBtn.style.visibility = \"visible\";\n                scrollTopBtn.style.transform = \"translateY(0)\";\n            } else {\n                scrollTopBtn.style.opacity = \"0\";\n                scrollTopBtn.style.visibility = \"hidden\";\n                scrollTopBtn.style.transform = \"translateY(1rem)\";\n            }\n        });\n\n        scrollTopBtn.addEventListener(\"click\", function() {\n            window.scrollTo({\n                top: 0,\n                behavior: \"smooth\"\n            });\n        });\n    }\n\n    // CTA Button hover effects\n    document.querySelectorAll(\".cta-button\").forEach(button =&gt; {\n        const gradient = button.querySelector(\".gradient-overlay\");\n\n        if (gradient) {\n            button.addEventListener(\"mouseenter\", function() {\n                gradient.style.opacity = \"1\";\n                button.style.transform = \"scale(1.05)\";\n            });\n\n            button.addEventListener(\"mouseleave\", function() {\n                gradient.style.opacity = \"0\";\n                button.style.transform = \"scale(1)\";\n            });\n        }\n    });\n\n    console.log(\"✅ Todas as funcionalidades carregadas com sucesso!\");\n});\n','Home','','inherit','closed','closed','','11-revision-v1','','','2026-01-18 04:38:25','2026-01-18 04:38:25','',11,'http://localhost:8000/?p=13',0,'revision','',0),(14,0,'2026-01-18 04:43:21','2026-01-18 04:43:21','','Home','','inherit','closed','closed','','11-revision-v1','','','2026-01-18 04:43:21','2026-01-18 04:43:21','',11,'http://localhost:8000/?p=14',0,'revision','',0),(15,1,'2026-01-18 04:57:50','0000-00-00 00:00:00','','Elementor #15','','draft','closed','closed','','','','','2026-01-18 04:57:50','2026-01-18 04:57:50','',0,'http